    public function getitems(Request $request)
    {
        if(request()->ajax())
        {
            //dd($request->serachtext,$request->itemid);
            
            $serachtext = $request->serachtext;
            $themeid = $request->itemid;
            $subthemes_array = [];
            
            //$theme_names = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
            
            if(empty($themeid))
            {
                $themes = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->get();
            }
            else
            {
                $themes = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
            }
            
            foreach($themes as $theme)
            {
                $subthemes_array[] = $theme->id;
            }
            
            if(!empty($serachtext))
            {
                $subthemes_data = Subtheme::withCount('subthemeimages')->with('theme')->whereIn('theme_id',$subthemes_array)->where('user_id','43')->where('sub_theme_name', 'like', "%$searchtext%")
                ->orWhereIn('theme_id', function($query) use ($searchtext) {
                    $query->select('id')->from('themes')->where('theme_name', 'like', "%$searchtext%")->orderBy('created_at','desc');
                })->get();
            }
            else
            {
                $subthemes_data = Subtheme::withCount('subthemeimages')->with('theme')->whereIn('theme_id',$subthemes_array)->where('user_id','43')->orderBy('created_at','desc')->get();
            }
            
            return $subthemes_data;
        }
    }
    
    public function savecuspaylater(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'name'=>'required',
                'last_name'=>'required',
                'email'=>'required|email',
                'phone'=>'required|numeric',
                'day'=>'required|numeric',
                'month'=>'required|numeric',
                'year'=>'required|numeric',
                'employment_type'=>'required',
                'loan_amt'=>'required|numeric',
                'monthly_salary'=>'required|numeric',
                'offc_pincode'=>'required|numeric',
                'residential_pincode'=>'required|numeric',
                'pan'=>'required',
                'gender'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {
                $name = $request->name;
                $last_name = $request->last_name;
                $email = $request->email;
                $phone = $request->phone;
                
                $day = $request->day;
                $month = $request->month;
                $year = $request->year;
                $employment_type = $request->employment_type;
                $monthly_salary = $request->monthly_salary;
                $offc_pincode = $request->offc_pincode;
                $residential_pincode = $request->residential_pincode;
                $pan = $request->pan;
                $gender = $request->gender;
                
                $loan_amt = $request->loan_amt ? $request->loan_amt : '';
                $quotation_number = $request->quotation_number ? $request->quotation_number : '';
               
                $item = new Cuspaylater();
                
                $item->cus_name = $name;
                $item->last_name = $last_name;
                $item->cus_email = $email;
                $item->cus_mobile = $phone;
                
                $item->day = $day;
                $item->month = $month;
                $item->year = $year;
                $item->employment_type = $employment_type;
                $item->monthly_salary = $monthly_salary;
                $item->offc_pincode = $offc_pincode;
                $item->residential_pincode = $residential_pincode;
                $item->pan = $pan;
                $item->gender = $gender;
                
                $item->loan_amt = $loan_amt;
                $item->quotation_number = $quotation_number;
                
                $order_id = 'planwed'.time();
                $item->order_id = $order_id;
                $earlysalary_token = $request->earlysalary_token;
                $isResendOtp = $request->isResendOtp;
    
                $resultString = [];
                
                if($item->save())
                {
                    $data = array('cus_name' => $name, 'cus_email' => $email, 'cus_mobile' => $phone, 'loan_amt' => $loan_amt, 'quotation_number' => $quotation_number);
                    
                    //$mailstatus = Mail::to('enquiry@planawedding.in')->send(new CusPaylaterMail($data));
                    
                    $mailstatus_2 = Mail::to($email)->send(new CusPaylaterMailCopy($data));

                    $mailstatus_2a = Mail::to(['weddingemi@planawedding.in'])->send(new CusPaylaterMailCopy($data));
                    
                    $send_otp = $this->sentOtpToCustomer($earlysalary_token,$order_id,$phone,$isResendOtp);

                    return response()->json([
                        'message' => 'Thank you for submitting your details, our team will connect with you shortly.',
                        'status' => '1',
                        'send_otp' => $send_otp,
                        'item_id' => $item->id,
                        'order_id' => $order_id,
                    ]);
                    
                    /*
                    return response()->json([
                        'message' => 'Thank you for submitting your details, our team will connect with you shortly.',
                        'status' => '1',
                    ]);
                    */
                }
                else
                {
                    return response()->json([
                        'message' => 'Error in submission. Please try again later.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }
    
    public function additemstocart(Request $request)
    {
        if($request->ajax())
        {
            $item_type = $request->item_type;
            $partidays = $request->day;
            $item_id = $request->item_id;
            $booking_type = $request->booking_type;
            $trans_type = $request->trans_type;
            $item_price = "";
            $net_price = "0";
            $size = "";
            $added_item_type = 'cart_entry';
            
            $item_qty = "";$item_height = "";$item_width = "";
            
            if($item_type == "Q")
            {
                $item_qty = $request->qty;
                $item_height = "";
                $item_width = "";
            }
            else if($item_type == "S")
            {
                $item_qty = "";
                $item_height = $request->height;
                $item_width = $request->width;
            }
            
			//for image, description and theme name
			
			$elementid = $request->item_id;            
            $itemdata = Subtheme::findOrFail($elementid);
            $itemimage = env('APP_URL')."/storage/".$itemdata->file;
            $sub_theme_name = $itemdata->sub_theme_name;
            //$particular = $itemdata->particular;
            $particular = $itemdata->sub_theme_name;
            $pack_desc = $itemdata->description;
            $theme_name = $itemdata->theme->theme_name;
            
			//for image, description and theme name ends
            
            $size = $request->size;
            
            if (empty($item_qty)) { 
                $item_qty = "";
            } 
            if (empty($item_height)) { 
                $item_height = "";
            } 
            if (empty($item_width)) { 
                $item_width = "";
            } 
            if (empty($item_price)) { 
                $item_price = "";
            } 
            if (empty($size)) { 
                $size = "";
            } 
            
            $single_cart_total = $net_price;
            
            $item_details = ['particular' => $particular,'item_qty' => $item_qty,'item_height' => $item_height,'item_width' => $item_width,
            'item_price' => $item_price,'net_price' => $net_price,'pack_desc' => $pack_desc,'partidays' => $partidays,'trans_type' => $trans_type,
            'single_cart_total' => $single_cart_total,'theme_name' => $theme_name,'added_item_type' => $added_item_type,'itemimage' => $itemimage,
            'size' => $size,'cart_item_type' => $item_type];

            $resultString = [];

            if($booking_type == 'cart_wedding')
            {
                $request->session()->push('weddingcart.items', $item_details);
                
                $booking_type_session = $request->session()->get('booking_type'); // added for new UI on Aug 16 2021
                
                if(empty($booking_type_session))
                {
                    $request->session()->put('booking_type', $booking_type);
                }
                
                $resultString['status'] = 1;
                $resultString['cart_items'] = $request->session()->get('weddingcart');
                echo(json_encode($resultString));
            }
            else
            {
                $resultString['status'] = 2;
                $resultString['cart_items'] = [];
                echo(json_encode($resultString));
            }
        }
    }
    
    public function saveweddingcalculator(Request $request)
    {
        if($request->ajax())
        {
            //dd($request);
            
            $name = $request->name;
            $email = $request->email;
            $phone = $request->phone;
            $pack_count = $request->pack_count;
            $event_date = $request->event_date;
            $itemlist = $request->itemlist;
            $pricelist = $request->pricelist;
           
            $item = new WeddingCalculator();
            
            $item->name = $name;
            $item->email = $email;
            $item->phone = $phone;
            $item->pack_count = $pack_count;
            $item->event_date = $event_date;
            $item->itemlist = $itemlist;
            $item->pricelist = $pricelist;
            
            $itemlist = explode('^^',$itemlist);
            $pricelist = explode('^^',$pricelist);
            
            $selected = "<ol>";
            
            for($i = 0;$i < count($itemlist); $i++)
            {
                $selected .= "<li>$itemlist[$i] - $pricelist[$i]</li>";
            }
            
            $selected .= "</ol>";
            
            $item->items = $selected;

            $resultString = [];

            if($item->save())
            {
                $resultString['status'] = 1;
                
                $data = array('name' => $name, 'email' => $email, 'phone' => $phone, 'pack_count' => $pack_count, 'event_date' => $event_date, 
                'itemlist' => $itemlist, 'pricelist' => $pricelist, 'allitems' => $selected);
                
                $mailstatus = Mail::to('enquiry@planawedding.in')->send(new WeddingCalculatorMail($data));
                
                //$mailstatus = Mail::to('samsrivastva@gmail.com')->send(new WeddingCalculatorMail($data));
    
                /*
                if (Mail::failures())
                {
                    return response()->json(['errors' => ['Mail can not send now. Please try later']]);
                }
                else
                {
                    return response()->json(['success' => 'Thank you for writing to us. Our team will call back shortly.']);
                }
                */
                
                echo(json_encode($resultString));
            }
            else
            {
                $resultString['status'] = 2;
                echo(json_encode($resultString));
            }
        }
    }
    
