    public function saveadform(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'name'=>'required',
                'email'=>'required|email',
                'phone_number'=>'required|digits:10',
                'city'=>'required',
                'weddingdate'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {
                $leadform = new LeadForm();
                
                $leadform->name = $request->name;
                $leadform->email = $request->email;
                $leadform->phone_number = $request->phone_number;
                
                $leadform->city = $request->city;
                $leadform->weddingdate = $request->weddingdate;
                
                $chosen_package = !empty($request->chosen_package) ? $request->chosen_package : "";
                $leadform->chosen_package = $chosen_package;
                
                if($leadform->save())
                {
                    $data = array('name' => $request->name, 'email' => $request->email, 'mobile' => $request->phone_number, 'chosen_package' => $chosen_package,
                    'city' => $request->city, 'weddingdate' => $request->weddingdate);
                
                    /*$mailstatus = Mail::to($request->email)->cc(['enquiry@planawedding.in'])->send(new AdFormMail($data));*/
                    
                    return response()->json([
                        /*'message' => 'Thank you for submitting your details. Our team will call you shortly',*/
                        'message' => '',
                        'status' => '1',
                    ]);
                    
                }
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }	
    
