  public function chatform(Request $request)
    {
        $allthemes = $this->allthemes();
        
        $theme_names = $allthemes[0];
        $theme_names1 = $allthemes[1];
		$theme_names2 = $allthemes[2];
		$theme_names3 = $allthemes[3];
		
        $homesliders = Homeslider::latest()->get();
        $coupon_texts = Coupontext::where('trans_type','general')->get();
        $coupon_texts = $coupon_texts->toArray();
        
        if (!empty($request->packagename))
        {
            $packagename = $request->packagename;
        }
        else
        {
            $packagename = "";
        }

        return view('website.chatform',compact(['coupon_texts','homesliders','theme_names','theme_names1','theme_names2','theme_names3','packagename']));
    }	
