    private function enquiryname($enquiryfor)
    {
        if($enquiryfor == '3.99')
        {
            return "3.99";
        }
        else if($enquiryfor == '4.99')
        {
            return "4.99";
        }
		else if($enquiryfor == '8.99')
        {
            return "8.99";
        }
		else if($enquiryfor == '9.89')
        {
            return "9.89";
        }
        else if($enquiryfor == 'Wedding Course')
        {
            return "Wedding Course";
        }
        else if($enquiryfor == 'Buy Leads')
        {
            return "Buy Leads";
        } 
        else if($enquiryfor == 'EMI')
        {
            return "EMI";
        }
    }
    
    
    
