                $txntype = $request->txntype;
            }
            else
            {
                $txntype = "";
            }
            
            if($type != 'lead' && $type != 'course')
            {
                return response()->json([
                    'message' => 'Invalid values passed for type.',
                ]);
            }
            
            if($amountpaypable > 0)
            {
                $amountpaypable = $amountpaypable.'.00';
                
                $orderid = time().'00'.$itemid;
                //$callBackUrl = route('paymentresult',$orderid);
                
                //$callBackUrl = 'https://www.business.planawedding.in/buy-leads.php?itemid='.$itemid.'&userid='.$user->id;
                
