			$callBackUrl = 'https://www.business.planawedding.in/thankyou.php?itemid='.$itemid;
                }
                
                 
                $cusId = $mobile;
                
                $paytmamount = $this->initiatetransaction($mobile,$cusId,$amountpaypable,$orderid,$callBackUrl);
                
                $paytmamount = json_decode($paytmamount, TRUE);
                
                //$txnToken = $paytmamount['body']['resultInfo']['resultCode'];
                $txnToken = $paytmamount['body']['txnToken'];
                
               
               
                
                $resultString['cusId'] = $cusId;
                $resultString['amount'] = $amountpaypable;
                $resultString['orderid'] = $orderid;
                $resultString['txnToken'] = $txnToken;
                $resultString['status'] = "1";
                
                return json_encode($resultString);
            }
            else
