    public function metaversewed(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'name'=>'required',
                'email'=>'required|email',
                'phone_number'=>'required|digits:10',
                'city'=>'required',
                'weddingdate'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {
                $leadform = new Metaverse();
                
                $leadform->name = $request->name;
                $leadform->email = $request->email;
                $leadform->phone_number = $request->phone_number;
                
                $leadform->city = $request->city;
                $leadform->weddingdate = $request->weddingdate;
                
                if($leadform->save())
                {
                    $data = array('name' => $request->name, 'email' => $request->email, 'mobile' => $request->phone_number, 'city' => $request->city, 
                    'weddingdate' => $request->weddingdate);
                
                    $mailstatus = Mail::to($request->email)->send(new MetaverseMail($data));
                    
                    $mailstatusa = Mail::to(['enquiry@planawedding.in'])->send(new MetaverseMail($data));

                    return response()->json([
                        'message' => 'Thank you for submitting your details. Our team will call you shortly',
                        'status' => '1',
                    ]);
                }
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }
    
