         $data_array = array('name' => $request->name , 'email' => $request->email, 'phone' => $request->phone, 'agreed_to_terms' => "yes");
            
            $request->session()->put('appointment_session1a', $data_array);
            
        $session_data = $request->session()->get('appointment_session1a');
        
        //dd($responsecode,$appointment_session);
       
         
            $name = $session_data['name'];
            $email = $session_data['email'];
            $phone = $session_data['phone'];
            $agreed_to_terms = "yes"; 
            
            $consultation = new Agreements();
            
            $consultation->name = $name;
            $consultation->email = $email;
            $consultation->phone = $phone;
            $consultation->agreed_to_terms = "yes"; 
            
            $data = array('name' => $name, 'email' => $email, 'phone' => $phone,
                    'agreed_to_terms' => $agreed_to_terms);
                
            $mailstatus = Mail::to('weddingemi@planawedding.in')->send(new AgreementMail($data));
            $mailstatus_2 = Mail::to($email)->cc(['weddingemi@planawedding.in'])->send(new AgreementCustomerMail($data));
            
            if($consultation->save())
            {
                $request->session()->forget('appointment_session1a');
                Session::save();
                
                $resultString['status'] = 1;
                echo(json_encode($resultString));
                //return redirect()->route('website.consultation')->with('meetstatus', 'Payment success. Our team will connect shortly');
            }
            else
            {
                $resultString['status'] = 2;
                echo(json_encode($resultString));
                //return redirect()->route('website.consultation')->with('meetstatus', 'Payment success. Error in sending mail. Please contact admin.');
            }
         
    }  	
    
    
     public function manualwedupload(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'email' => 'required|email',
                'name' => 'required',
                'mobile' => 'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {
                $customer = new Customer();
                
                $customer->name = $request->name;
                $customer->email = $request->email;
                $customer->mobile = $request->mobile;
                $customer->lead_source = "website";
                
                if($customer->save())
                {
                    return response()->json([
                        'message' => 'customer saved',
                        'status' => '1',
                    ]);
                }
                else
                {
                    return response()->json([
                        'message' => 'customer not saved',
                        'status' => '0',
                    ]);
                }
            }
        }
    }
    
