    public function businesspaw(Request $request,$id)
    {
        
        $urls = $id;
        
        $homesliders = Homeslider::latest()->get();
        
        $allthemes = $this->allthemes();
        
        $theme_names = $allthemes[0];
        $theme_names1 = $allthemes[1];
		$theme_names2 = $allthemes[2];
		$theme_names3 = $allthemes[3];
		
		$page_items = Item::where('type','marriage')->first();
        $coupon_texts = Coupontext::where('trans_type','homepage')->get();
        $coupon_texts = $coupon_texts->toArray();
        
        $cart_items = [];    
        $subthemes_array = [];

        if ($request->session()->has('weddingcart')) {
            $cart_items = $request->session()->get('weddingcart');
        }

        foreach($theme_names1 as $theme)
        {
            $subthemes_array[] = $theme->id;
        }
        
        $subthemes_data = Subtheme::withCount('subthemeimages')->whereIn('theme_id',$subthemes_array)->where('user_id','43')->get();
        
        $subthemes_data = $subthemes_data->whereIn('theme_id',$subthemes_array);
        
         $result = json_decode($this->earlysalary());
        
        $earlysalary_token = $result->token;
                
        return view('website.businesspaw', compact(['urls','homesliders','coupon_texts','theme_names','theme_names1','theme_names2','theme_names3','cart_items','page_items','subthemes_data','earlysalary_token']));
    }
    
    public function paylater(Request $request,$id)
    {
        $urls = $id;
        $url = decrypt($id);
        $id = decrypt($id);
        
        $data = Epquotation::where('id',$id)->first();
        
        if($data)
        {
            $allthemes = $this->allthemes();
        
            $theme_names = $allthemes[0];
            $theme_names1 = $allthemes[1];
    		$theme_names2 = $allthemes[2];
    		$theme_names3 = $allthemes[3];
    		
            $homesliders = Homeslider::latest()->get();
            $coupon_texts = Coupontext::where('trans_type','general')->get();
            $coupon_texts = $coupon_texts->toArray();
            
            $quotation_number = $data->quotation_number;
            $name = $data->name;
            $email = $data->email;
            $mobile = $data->mobile;

