        $theme_names1 = $allthemes[1];
		$theme_names2 = $allthemes[2];
		$theme_names3 = $allthemes[3];
		
        $homesliders = Homeslider::latest()->get();
        $coupon_texts = Coupontext::where('trans_type','general')->get();
        $coupon_texts = $coupon_texts->toArray();
        
        $cart_type = 'weddingcart.items';
        
        $cart_items = $request->session()->get($cart_type);
        
        if(empty($cart_items))
        {
            return redirect()->route('homepage');
        }

        return view('website.cart',compact(['coupon_texts','homesliders','cart_items','theme_names','theme_names1','theme_names2','theme_names3']));
    }
    
    public function cartajax(Request $request, $cart_type)
    {
        if($request->ajax())
        {
            $resultString = [];

            if ($request->session()->has($cart_type)) 
            {
                $resultString['status'] = 1;
                $resultString['cart_items'] = $request->session()->get($cart_type);
            }
            else
            {
                $resultString['status'] = 2;
                $resultString['cart_items'] = array();
            }
            echo(json_encode($resultString));            
        }
    }
    
    public function privacypolicy()
    {
