    public function additemstocart_old(Request $request)
    {
        if($request->ajax())
        {
            $particular = $request->particular;
            $item_qty = $request->item_qty;
            $item_height = $request->item_height;
            $item_width = $request->item_width;
            $item_price = $request->item_price;
            $net_price = $request->net_price;
            $pack_desc = $request->pack_desc;
            $partidays = $request->partidays;
            $trans_type = $request->trans_type;
            $theme_name = $request->theme_name;
            
            $booking_type = $request->booking_type;
            $added_item_type = $request->added_item_type;
            
            //$request->session()->put('booking_type', $booking_type);
            //above session will be set with the checkout buttons after clicking add to cart 
			
			//for image 
			$elementid = $request->elementid;            
            $imagedata = Subtheme::findOrFail($elementid);
            $itemimage = env('APP_URL')."/storage/".$imagedata->file;
			//for image ends
            
            $size = $request->size;
            
            if (empty($item_qty)) { 
                $item_qty = "";
            } 
            if (empty($item_height)) { 
                $item_height = "";
            } 
            if (empty($item_width)) { 
                $item_width = "";
            } 
            if (empty($item_price)) { 
                $item_price = "";
            } 
            if (empty($size)) { 
                $size = "";
            } 
            $single_cart_total = $net_price;
            
            if($booking_type == 'cart_corpgift')
            {
                $gst_applicable = $request->gst_applicable;
                
                $item_details = ['particular' => $particular,'item_qty' => $item_qty,'item_height' => $item_height,'item_width' => $item_width,'item_price' => $item_price,'net_price' => $net_price,'pack_desc' => $pack_desc,'partidays' => $partidays,'trans_type' => $trans_type,'single_cart_total' => $single_cart_total,'theme_name' => $theme_name,'added_item_type' => $added_item_type,'itemimage' => $itemimage,'size' => $size,'gst_applicable' => $gst_applicable];
            }
