    public function paymentupdate(Request $request,$id)
    {
        $banktxnid = $request->BANKTXNID;
        $orderid = $request->ORDERID;
        $responsecode = $request->RESPCODE;
        $txndate = $request->TXNDATE;
        $txnid = $request->TXNID;
        
        $urls = $id;
        $url = decrypt($id);
        $id = decrypt($id);
        
        $fullUrl = $request->fullUrl();
        
        //dd($urls,$url,$id,$request->fullUrl());
        
        if($responsecode == "01")
        {
            $mailStaus = $this->updatepaytmpayment($id,$txnid);
            
            if($mailStaus)
            {
                return redirect()->route('payment',['id' => $urls])->with('paymentstaus', 'Transaction Success.');
            }
            else
            {
                return redirect()->route('payment',['id' => $urls])->with('paymentstaus', 'Transaction Success. Error in sending mail.');
            }
        }
        else
        {
            return redirect()->route('payment',['id' => $urls])->with('paymentstaus', 'Transaction Failed. Please Try again later.');
        }
    }
    
