    public function weddingenquiry(Request $request)
    {
        $homesliders = Homeslider::latest()->get();
        $trans_type = 'equipment'; $event_date = ''; $coupon_texts = ''; $promocode = ''; $booking_type = 'cart_single';
        
        if ($request->session()->has('event_date'))
        {
            $event_date = $request->session()->get('event_date');
        }
        
        $coupon_texts = Coupontext::where('trans_type',$trans_type)->get();
        $coupon_texts = $coupon_texts->toArray();
        
        if ($request->session()->has('promocode'))
        {
            $promocode = $request->session()->get('promocode'); 
        }
        
        $singlecart = ['particular' => 'Special Wedding Package Booking','item_qty' => '1','item_height' => '','item_width' => '','item_price' => '0','net_price' => '0','pack_desc' => 'Wedding package','partidays' => '1','trans_type' => $trans_type,'single_cart_total' => '0','size' => ''];
        $cartdata = $request->session()->put('singlecart', $singlecart);
        $request->session()->put('booking_type', $booking_type);
        
        return view('website.wedding-enquiry',compact(['trans_type','event_date','coupon_texts','promocode','booking_type','homesliders'])); 
    }

