    private function deletesession($request)
    {
        if ($request->session()->has('opt_input')) 
        {
            $request->session()->forget('opt_input');
            Session::save();
        }
        if ($request->session()->has('promocode')) 
        {
            $request->session()->forget('promocode');
            Session::save();
        }
        if ($request->session()->has('event_date')) 
        {
            $request->session()->forget('event_date');
            Session::save();
        }
        if ($request->session()->has('booking_type')) 
        {
            $booking_type = $request->session()->get('booking_type'); 

            if($booking_type == 'cart_single') 
            {
                if ($request->session()->has('singlecart')) 
                {
                    $request->session()->forget('singlecart');
                }
            }
            else if($booking_type == 'cart_wedding') 
            {
                if ($request->session()->has('weddingcart')) 
                {
                    $request->session()->forget('weddingcart');
                }
            }
			else if($booking_type == 'cart_birthday') 
            {
                if ($request->session()->has('birthdaycart')) 
                {
                    $request->session()->forget('birthdaycart');
                }
            }
			else if($booking_type == 'cart_equipment') 
            {
                if ($request->session()->has('equipmentcart')) 
                {
                    $request->session()->forget('equipmentcart');
                }
            }
            else if($booking_type == 'cart_corporate') 
            {
                if ($request->session()->has('corporatecart')) 
                {
                    $request->session()->forget('corporatecart');
                }
            }
            else if($booking_type == 'cart_corpgift') 
            {
                if ($request->session()->has('corpgiftcart')) 
                {
                    $request->session()->forget('corpgiftcart');
                }
            }
            else if($booking_type == 'cart_shaadi') 
            {
                if ($request->session()->has('shaadicart')) 
                {
                    $request->session()->forget('shaadicart');
                }
            }
            else if($booking_type == 'cart_general') 
            {
                if ($request->session()->has('generalcart')) 
                {
                    $request->session()->forget('generalcart');
                }
            }
            $request->session()->forget('booking_type');
            Session::save();
        }
    }
    
    public function corporateregister(Request $request)
    {
        $homesliders = Homeslider::latest()->get();
        $coupon_texts = Coupontext::where('trans_type','general')->get();
        $coupon_texts = $coupon_texts->toArray();

        return view('website.corporateregister',compact(['coupon_texts','homesliders']));
    }
    
    public function corpregister(Request $request)
    {
        $resultString = [];
        
        if($request->ajax())
        {
            $cus_name = '';$cus_email = '';$cus_mobile = '';$cus_gstnumber = '';$cus_pannumber = '';$cus_business_name = '';

            /****************Data from single booking form comes here***************************/
            
            $business_name = $request->business_name;
            $name = $request->name;
            $mobile = $request->mobile;
			
			$email = $request->email;
			$gstnumber = $request->gstnumber;
			$pannumber = $request->pannumber;
			
			if(empty($gstnumber))
			{
			    $gstnumber = "";
			}
			if(empty($pannumber))
			{
			    $pannumber = "";
			}
			
			$user = User::where('email',"$email")->get();
			
			if(count($user) > 0)
			{
			    $resultString['status'] = 2;
                $resultString['message'] = 'Email address given is already in use.';
                echo(json_encode($resultString));
                
                return;
			}
			
            $data =  new User();

            $data->business_name = $business_name;
            $data->name = $name;
            $data->email = $email;
            $data->username = $email;
            
            $data->toss_actual_pass = $mobile;
