    public function leadpaymentauth(Request $request)
    {
        $orderid = time();
        $fullUrl = route('leadsubscriptionres');
        $amountpaypable = $request->amount;
        $cusId = uniqid();
        
        $paytmamount = $this->paytmpayment($cusId,$amountpaypable,$orderid,$fullUrl);
        
        $paytmamount = json_decode($paytmamount, TRUE);
        
        $txnToken = $paytmamount['body']['txnToken'];
        
        $resultString['cusId'] = $cusId;
        $resultString['amount'] = $amountpaypable;
        $resultString['orderid'] = $orderid;
        $resultString['txnToken'] = $txnToken;

        echo(json_encode($resultString));
    }
    
