    public function yoeevideos(Request $request)
    {       
        $route_name = $request->route()->getName() == 'website.yoeebdayvideos' ? 'birthday' : 'wedding';
        
        $route_name_2 = $request->route()->getName() == 'website.yoeebdayvideos' ? 'birthday' : 'marriage';
        
        $route_name_3 = $request->route()->getName() == 'website.yoeebdayvideos' ? 'bdayvideo' : 'weddingvideo';
        
