    public function changecity(Request $request)
    {
        $resultString = [];
        
        if($request->ajax())
        {
            //dd($request->city);
            
            if($request->city == "bangalore" || $request->city == "hyderabad" || $request->city == "jaipur" || $request->city == "ahmedabad" || $request->city == "delhi")
            {
                $city = ucfirst($request->city);
                $request->session()->put('sessioncity', $city);
                
                $resultString['status'] = 1;
                $resultString['sessioncity'] = $city;
                
                $citydata = City::where('name',"$request->city")->latest()->first();
                $resultString['sessioncityid'] = $citydata->id;
            }
            else
            {
                $resultString['status'] = 2;
                $resultString['sessioncity'] = "";
                $resultString['sessioncityid'] = "";
            }
        }
        else
        {
            $resultString['status'] = 2;
            $resultString['sessioncity'] = "";
            $resultString['sessioncityid'] = "";
        }
        
        echo(json_encode($resultString));
    }
    
    public function eventplanner(Request $request)
    {
        $user = User::where('thcode',"$request->thcode")->where('role_id',4)->where('is_active',1)->first();
        
        if($user)
        {
            $homesliders = Homeslider::latest()->get();
            $coupon_texts = Coupontext::where('trans_type','homepage')->get();
            $coupon_texts = $coupon_texts->toArray();
            
            $wedding_count = Subtheme::where('user_id',$user->id)->get()->count();
            $equipment_count = Subtheme::where('user_id',$user->id)->get()->count();
            $birthday_count = Subtheme::where('user_id',$user->id)->get()->count();
            
            //dd($wedding_count,$equipment_count,$birthday_count);
    
            return view('website.eventplanner', compact(['homesliders','coupon_texts','user','wedding_count','equipment_count','birthday_count']));
        }
        else
        {
            return redirect()->route('homepage');
        }
    }
    
    public function eventplanneritems(Request $request)
    {
        $itemtype = $request->itemtype;
        
        if($itemtype != "weddings" && $itemtype != "birthdays" && $itemtype != "corporate")
        {
            return redirect()->route('homepage');
        }
        
        if($itemtype == "weddings")
        {
            $itemTocare = "marriage";
            $itemToDiv = "wedding";
            $data_bookingtype_item = "epcart_wedding";
        }
        if($itemtype == "corporate")
        {
            $itemTocare = "equipment";
            $itemToDiv = "equipment";
            $data_bookingtype_item = "epcart_equipment";
        }
        if($itemtype == "birthdays")
        {
            $itemTocare = "birthday";
            $itemToDiv = "birthday";
            $data_bookingtype_item = "epcart_birthday";
