        $user = User::where('thcode',"$request->thcode")->where('role_id',4)->where('is_active',1)->first();
        
        $cities = $user->city;
        $cities = explode(",",$cities);
        $eventplanner_city = $cities['0'];
        
        if($user)
        {
            $homesliders = Homeslider::latest()->get();
            
            if($itemtype == "birthdays")
            {
