    public function epadditemstocart(Request $request)
    {
        if($request->ajax())
        {
            if(($request->eventplanner_id == $request->session()->get('eventplanner_thcode')) || empty($request->session()->get('eventplanner_thcode')))
            {
                $particular = $request->particular;
                $item_qty = $request->item_qty;
                $pack_desc = $request->pack_desc;
                $partidays = $request->partidays;
                $item_height = $request->item_height;
                $item_width = $request->item_width;
                $net_price = $request->net_price;
                $trans_type = $request->trans_type;
                $booking_type = $request->booking_type;
                $theme_name = $request->theme_name;
                $added_item_type = $request->added_item_type;
                $elementid = $request->elementid;
                $size = $request->size;
                $thcode = $request->eventplanner_id;
                $item_price = $request->item_price;
                
                $eventplanner_price = $request->eventplanner_price;
                $eventplanner_city = $request->eventplanner_city;
                
                $request->session()->put('eventplanner_city', $eventplanner_city);
                $request->session()->put('eventplanner_thcode', $thcode);
    
                //$request->session()->put('booking_type', $booking_type);
                //above session will be set with the checkout buttons after clicking add to cart 
    			
    			//for image 
    			           
                $imagedata = Subtheme::findOrFail($elementid);
                $itemimage = env('APP_URL')."/storage/".$imagedata->file;
    			//for image ends
                
                if (empty($item_qty)) { 
                    $item_qty = "";
                } 
                if (empty($item_height)) { 
                    $item_height = "";
                } 
                if (empty($item_width)) { 
                    $item_width = "";
                } 
                if (empty($item_price)) { 
                    $item_price = "";
                } 
                if (empty($size)) { 
                    $size = "";
                } 
                
                $single_cart_total = $net_price;
    
                $item_details = ['particular' => $particular,'item_qty' => $item_qty,'item_height' => $item_height,'item_width' => $item_width,'item_price' => $item_price,'net_price' => $net_price,'pack_desc' => $pack_desc,'partidays' => $partidays,'trans_type' => $trans_type,'single_cart_total' => $single_cart_total,'theme_name' => $theme_name,'added_item_type' => $added_item_type,'itemimage' => $itemimage,'size' => $size,'eventplanner_price' => $eventplanner_price];
    
                $resultString = [];
    
                if($booking_type == 'epcart_wedding')
                {
                    $request->session()->push('epweddingcart.items', $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('epweddingcart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
                else if($booking_type == 'epcart_birthday')
                {
                    $cart_details = 'epbirthdaycart.'.$trans_type ;
    
                    $request->session()->push($cart_details, $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('epbirthdaycart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
    			else if($booking_type == 'epcart_equipment')
                {
                    $cart_details = 'epequipmentcart.'.$trans_type ;
    
                    $request->session()->push($cart_details, $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('epequipmentcart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
                else if($booking_type == 'yoeecart_wedding')
                {
                    $request->session()->push('yoeeweddingcart.items', $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('yoeeweddingcart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
                else if($booking_type == 'yoeecart_birthday')
                {
                    $cart_details = 'yoeebirthdaycart.'.$trans_type ;
    
                    $request->session()->push($cart_details, $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('yoeebirthdaycart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
    			else if($booking_type == 'yoeecart_equipment')
                {
                    $cart_details = 'yoeeequipmentcart.'.$trans_type ;
    
                    $request->session()->push($cart_details, $item_details);
    
                    $resultString['status'] = 1;
                    $resultString['cart_items'] = $request->session()->get('yoeeequipmentcart');
                    $resultString['eventplanner_thcode'] = $request->session()->get('eventplanner_thcode');
                    echo(json_encode($resultString));
                }
                else
                {
                    $resultString['status'] = 2;
                    $resultString['cart_items'] = [];
                    $resultString['eventplanner_thcode'] = "";
                    echo(json_encode($resultString));
                }
            }
            else
            {
                $resultString['status'] = 3;
                $resultString['cart_items'] = [];
                $resultString['eventplanner_thcode'] = "";
                echo(json_encode($resultString));
            }
        }
    }
    
    public function epremovecartitem(Request $request)
    {
        if($request->ajax())
        {
            $item_id = $request->item_id;
            $cart_type = $request->cart_type;
            $item_type = $request->item_type;
            $resultString = [];

            if($cart_type == 'epweddingcart')
            {
                $remove_id = 'epweddingcart.items.'.$item_id;
                $cart_details = 'epweddingcart';
            }
            else if($cart_type == 'epbirthdaycart')
            {
                $remove_id = 'epbirthdaycart.'.$item_type.'.'.$item_id;
                $cart_details = 'epbirthdaycart';
            }
			else if($cart_type == 'epequipmentcart')
            {
                $remove_id = 'epequipmentcart.'.$item_type.'.'.$item_id;
                $cart_details = 'epequipmentcart';
            }
            else if($cart_type == 'yoeeweddingcart')
            {
                $remove_id = 'yoeeweddingcart.items.'.$item_id;
                $cart_details = 'yoeeweddingcart';
            }
            else if($cart_type == 'yoeebirthdaycart')
            {
                $remove_id = 'yoeebirthdaycart.'.$item_type.'.'.$item_id;
                $cart_details = 'yoeebirthdaycart';
            }
			else if($cart_type == 'yoeeequipmentcart')
            {
                $remove_id = 'yoeeequipmentcart.'.$item_type.'.'.$item_id;
                $cart_details = 'yoeeequipmentcart';
            }
            
            //dd($request->session()->get($cart_details));
           
            $request->session()->forget($remove_id);
            Session::save();

            if ($request->session()->has($cart_details)) 
            {
                $resultString['status'] = 1;
                $resultString['cart_items'] = $request->session()->get($cart_details);
            }
            else
            {
                $resultString['status'] = 2;
                $resultString['cart_items'] = array();
            }
            echo(json_encode($resultString));            
        }
    }

