    public function resetcart(Request $request)
    {
        if($request->ajax())
        {
            $resultString = [];
            $status = 0;
            
            if ($request->session()->has('epweddingcart')) 
            {
                $request->session()->forget('epweddingcart');
                $status = 1;
            }
            if ($request->session()->has('epbirthdaycart')) 
            {
                $request->session()->forget('epbirthdaycart');
                $status = 1;
            }
            if ($request->session()->has('epequipmentcart')) 
            {
                $request->session()->forget('epequipmentcart');
                $status = 1;
            }
            if ($request->session()->has('eventplanner_thcode')) 
            {
                $request->session()->forget('eventplanner_thcode');
                $status = 1;
            }
            
            Session::save();
            $resultString['resetstatus'] = $status;
            echo(json_encode($resultString));
        }
    }
    
