    public function epthemenames(Request $request)
    {
        if(request()->ajax())
        {
            $itemtype = $request->itemtype;
        
            if($itemtype != "weddings" && $itemtype != "birthdays" && $itemtype != "corporate")
            {
                return redirect()->route('homepage');
            }
            
            if($itemtype == "weddings")
            {
                $itemTocare = "marriage";
                $itemToDiv = "wedding";
                $data_bookingtype_item = "yoeecart_wedding";
            }
            if($itemtype == "corporate")
            {
                $itemTocare = "equipment";
                $itemToDiv = "equipment";
                $data_bookingtype_item = "yoeecart_equipment";
            }
            if($itemtype == "birthdays")
            {
                $itemTocare = "birthday";
                $itemToDiv = "birthday";
                $data_bookingtype_item = "yoeecart_birthday";
            }
            
            $user = User::where('thcode',"$request->thcode")->where('role_id',4)->where('is_active',1)->first();

            if($user)
            {
                if($itemtype == "birthdays")
                {
                    $theme_names = Theme::with('subthemes')->where('theme_type',"$itemTocare")->where('user_id',$user->id)->whereHas('subthemes', function($query) use ($user)
                    {
                        $query->where('subthemes.user_id',$user->id);
                    
                    })->get();
                }
                else
                {
                    $theme_names = Theme::with('subthemes')->where('theme_type',"$itemTocare")->whereHas('subthemes', function($query) use ($user)
                    {
                        $query->where('subthemes.user_id',$user->id);
                    
                    })->get();
                }
                
                //dd($theme_names);
        
                return $theme_names;
            }
        }
    }
    
    public function resetcartyoee(Request $request)
    {
        if($request->ajax())
        {
            $resultString = [];
            $status = 0;
            
            if ($request->session()->has('yoeeweddingcart')) 
            {
                $request->session()->forget('yoeeweddingcart');
                $resultString['booking_type'] = "yoeecart_wedding";
                $resultString['cart_items'] = $request->session()->get('yoeeweddingcart.items');
                $status = 1;
            }
            if ($request->session()->has('yoeebirthdaycart')) 
            {
                $request->session()->forget('yoeebirthdaycart');
                $resultString['booking_type'] = "yoeecart_birthday";
                $resultString['cart_items'] = $request->session()->get('yoeebirthdaycart');
                $status = 1;
            }
            if ($request->session()->has('yoeeequipmentcart')) 
            {
                $request->session()->forget('yoeeequipmentcart');
                $resultString['booking_type'] = "yoeecart_equipment";
                $resultString['cart_items'] = $request->session()->get('yoeeequipmentcart');
                $status = 1;
            }
            if ($request->session()->has('eventplanner_thcode')) 
            {
                $request->session()->forget('eventplanner_thcode');
                $status = 1;
            }
            
            Session::save();
            $resultString['resetstatus'] = $status;
            $resultString['eventplanner_thcode'] = $request->session()->has('eventplanner_thcode') ? $request->session()->get('eventplanner_thcode') : "";
            echo(json_encode($resultString));
        }
    }
    
