            $appointment_description = $request->appointment_description;
            $duration = $request->duration;
            $appointment_for = $request->appointment_for;
            $amount = $request->amountpaypable;
            $orderid = $request->orderid;
            
            $consultation = new Consultation();
            
            $consultation->name = $name;
            $consultation->email = $email;
            $consultation->phone = $phone;
            $consultation->appointment_date = $appointment_date;
            $consultation->appointment_time = $appointment_time;
            $consultation->address = $address;
            $consultation->appointment_description = $appointment_description;
            $consultation->duration = $duration;
            $consultation->appointment_for = $appointment_for;
            $consultation->amount = $amount;
            $consultation->orderid = $orderid;
            
            $resultString = [];
            
            $data = array('name' => $name, 'email' => $email, 'phone' => $phone, 'appointment_date' => $appointment_date, 'appointment_time' => $appointment_time, 
