    private function earlysalary() 
    {
        $data = array(
            'username' => 'YoeeUser',
            'password' => 'Y0e$%12Prod',
        	'applicationName' => 'WEB'
        );
         
        // Convert the PHP array into a JSON format
        $payload = json_encode($data);
         
        // Initialise new cURL session
        $ch = curl_init('https://agtr-prod.earlysalary.com/generateToken');
        
        // Return result of POST request
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        
        // Get information about last transfer
        curl_setopt($ch, CURLINFO_HEADER_OUT, true);
        
        // Use POST request
        curl_setopt($ch, CURLOPT_POST, true);
        
        // Set payload for POST request
        curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);
         
        // Set HTTP Header for POST request 
        curl_setopt($ch, CURLOPT_HTTPHEADER, array(
            'Content-Type: application/json',
            'Content-Length: ' . strlen($payload))
        );
         
