        $homesliders = Homeslider::latest()->get();
        
        
        $allthemes = $this->allthemes();
        
        $theme_names = $allthemes[0];
        $theme_names1 = $allthemes[1];
		$theme_names2 = $allthemes[2];
		$theme_names3 = $allthemes[3];
         
		
        $honeymoons = Honeymoon::all();
            
        $honeymooncity = Honeymoon::groupBy('destination')->get();
         

		$page_items = Item::where('type','marriage')->first();
        $coupon_texts = Coupontext::where('trans_type','homepage')->get();
        $coupon_texts = $coupon_texts->toArray();
        
        $cart_items = [];    
        $subthemes_array = [];

        if ($request->session()->has('weddingcart')) {
            $cart_items = $request->session()->get('weddingcart');
        }

        foreach($theme_names1 as $theme)
        {
            $subthemes_array[] = $theme->id;
        }
        
        $subthemes_data = Subtheme::withCount('subthemeimages')->whereIn('theme_id',$subthemes_array)->where('user_id','43')->orderBy('id','desc')->get();
        
        $subthemes_data = $subthemes_data->whereIn('theme_id',$subthemes_array);
                
        return view('website.honeymoon', compact(['homesliders','coupon_texts','theme_names','theme_names1','theme_names2','theme_names3','cart_items','page_items','subthemes_data','honeymoons','honeymooncity']));
    }


    public function gethoneymoonitems(Request $request)
    {
        if(request()->ajax())
        {
            //dd($request->serachtext,$request->itemid);
            
            $serachtext = $request->serachtext;
            $themeid = $request->itemid;
            $themename = $request->themename;
            $subthemes_array = [];
            
            //$theme_names = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
            

            if(empty($themeid))
            {
                $themes = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->get();
            }
            else
            {
                //$themes = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
                $themes = Honeymoon::where('destination',$themename)->get();
            }
             

            foreach($themes as $theme)
            {
                $subthemes_array[] = $theme->destination;
            }
            
            if(!empty($serachtext))
            {
                $subthemes_data = Honeymoon::whereIn('destination',$subthemes_array)->where('destination', 'like', "%$searchtext%")
                ->orWhereIn('destination', function($query) use ($searchtext) {
                    $query->select('destination')->from('honeymoons')->where('destination', 'like', "%$searchtext%")->orderBy('created_at','desc');
                })->get();
            }
            else
            {
                $subthemes_data = Honeymoon::whereIn('destination',$subthemes_array)->orderBy('created_at','desc')->get();
            }
            
            return $subthemes_data;
        }
    }


