    public function weddingpackagesbp(Request $request)
    {
        $homesliders = Homeslider::latest()->get();
        
        
        $allthemes = $this->allthemes();
        
        $theme_names = $allthemes[0];
        $theme_names1 = $allthemes[1];
        $theme_names2 = $allthemes[2];
        $theme_names3 = $allthemes[3];
        
        
        $honeymoons = Honeymoon::all();
            
        $wppackages = User::where('role_id',4)->where('is_active',1)
        ->Join("weddingplanner_packages","users.id","=","weddingplanner_packages.user_id")
        ->where('weddingplanner_packages.package_city','Bangalore')
        ->where('weddingplanner_packages.active_disable',0)
        ->where('weddingplanner_packages.enable_package','1')
        ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
        ->get();
        
         
        $packagecity1 = WpplannerPackage::groupBy('package_city')
        ->where('enable_package','1')->where('active_disable',0)->get();
        
        $packagecity2 = PackageCities::groupBy('city_name')
        ->where('city_active',1)->get();

        $packagecity = WpplannerPackage::groupBy('weddingplanner_packages.mapped_city_name')
        ->Join("cities_packages","weddingplanner_packages.map_city","=","cities_packages.id")
        ->Join("users","weddingplanner_packages.user_id","=","users.id")
        ->where('users.is_active',1)
        ->where('weddingplanner_packages.enable_package','1')
        ->where('weddingplanner_packages.active_disable',0)
        ->orderBy('weddingplanner_packages.map_city','asc')
        ->get();
 
        $packageStatess = PackageState::groupBy('package_states.state_name') 
        ->Join("weddingplanner_packages","package_states.id","=","weddingplanner_packages.map_state")
        ->Join("users","weddingplanner_packages.user_id","=","users.id")
        ->where('users.is_active',1)
        /*->where('users.wallet_amount','>=',500)*/
        ->where('package_states.show_in_live','1') 
        ->where('weddingplanner_packages.enable_package','1')
        ->where('weddingplanner_packages.active_disable',0)
        ->orderBy('package_states.state_name','asc')
        ->get();

