    public function saveenquiry(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'yournamess'=>'required',
                'youremail'=>'required|email',
                'yournumber'=>'required|digits:10',
                 'yourcity'=>'required',
                  'youreventdate'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {
                
                $leadtime = date("d-m-Y h:i:s");
                
               

                $CustomEnquiry = new CustomEnquiry();
                
                $CustomEnquiry->comapnyname = $request->yournamess;
                $CustomEnquiry->mobile = $request->yournumber;
                $CustomEnquiry->email = $request->youremail;
                
                $CustomEnquiry->city = $request->yourcity;
                $CustomEnquiry->eventdate = $request->youreventdate; 
                 


                $CustomEnquiry->enquired_on = $leadtime;
                
               
                
                if($CustomEnquiry->save())
                {
                    
                      
                    return response()->json([
                        'message' => 'Thank you for submitting your details. Our team will call you shortly', 
                         
                        'status' => '1',
                    ]);
                    
                }
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }
    
