    public function getweddingpackagesbpitems(Request $request)
    {
        if(request()->ajax())
        {
            //dd($request->serachtext,$request->itemid);
            
            $serachtext = $request->serachtext;
            $themeid = $request->itemid;
            $themename = $request->themename;

            $statename = $request->statename;

            $subthemes_array = [];
            
            //$theme_names = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
            
             
            if(empty($themeid))
            {
                $themes = WpplannerPackage::where('package_city',$themeid)->where('enable_package','1')
                ->where('active_disable',0)->orderByRaw('CONVERT(package_amount, SIGNED) asc')
                ->get();
            }
            else
            {
                //$themes = Theme::has('subthemes')->with('subthemes')->where('theme_type','marriage')->where('user_id','43')->where('id',$themeid)->get();
                $themes = WpplannerPackage::where('package_city','LIKE',"%{$themename}%")->where('enable_package','1')
                ->where('active_disable',0)->orderByRaw('CONVERT(package_amount, SIGNED) asc')
                ->get();
            }
               

            foreach($themes as $theme)
            {
                $subthemes_array[] = $theme->package_city;
            }
            

            if(!empty($serachtext))
            {
                $subthemes_data = Honeymoon::whereIn('destination',$subthemes_array)->where('destination', 'like', "%$searchtext%")
                ->orWhereIn('destination', function($query) use ($searchtext) {
                    $query->select('destination')->from('honeymoons')->where('destination', 'like', "%$searchtext%")->orderBy('created_at','desc');
                })->get();
            }
            else
            {
                /*
                    $subthemes_data = 
                    User::where('role_id',4)->where('is_active',1)->where('wallet_amount','>=',500)
                    ->Join("weddingplanner_packages","users.id","=","weddingplanner_packages.user_id")
                    ->whereIn('weddingplanner_packages.package_city',$subthemes_array) 
                    ->where('weddingplanner_packages.active_disable',0)
                    ->where('weddingplanner_packages.enable_package','1')
                    ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
                    ->get(); 
                */  
                
                
                
                
                if(!empty($statename) && empty($themename))
                {
                    $subthemes_data = 
                    User::where('role_id',4)->where('is_active',1)
                    ->Join("weddingplanner_packages","users.id","=","weddingplanner_packages.user_id")
                    ->where('weddingplanner_packages.mapped_state_name',$statename)  
                    ->where(function ($query) {
                        $query->where('weddingplanner_packages.active_disable',0)
                        ->where('weddingplanner_packages.enable_package','1')
                        ->where('users.display_wedding_package',"yes");
                    })
                    //->where('users.wallet_amount','>',500)
                    ->where('users.is_partner','1')
                    ->where('users.chk_subscription','0')
                    ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
                    ->get();
                }
                if(!empty($statename) && !empty($themename))
                {
                    $subthemes_data = 
                    User::where('role_id',4)->where('is_active',1)
                    ->Join("weddingplanner_packages","users.id","=","weddingplanner_packages.user_id")
                    ->where('weddingplanner_packages.mapped_state_name',$statename) 
                    ->where('weddingplanner_packages.mapped_city_name',$themename) 
                    ->where(function ($query) {
                        $query->where('weddingplanner_packages.active_disable',0)
                        ->where('weddingplanner_packages.enable_package','1')
                        ->where('users.display_wedding_package',"yes");
                    })
                    //->where('users.wallet_amount','>',500)
                    ->where('users.is_partner','1')
                    ->where('users.chk_subscription','0')
                    ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
                    ->get();
                }

              
                 
                if(empty($statename) && empty($themename))
                {
                    $subthemes_data = 
                    User::where('role_id',4)->where('is_active',1)
                    ->Join("weddingplanner_packages","users.id","=","weddingplanner_packages.user_id")
                    ->whereIn('weddingplanner_packages.package_city',$subthemes_array) 
                    ->where(function ($query) {
                        $query->where('weddingplanner_packages.active_disable',0)
                        ->where('weddingplanner_packages.enable_package','1')
                        ->where('users.display_wedding_package',"yes");
                    })
                    //->where('users.wallet_amount','>',500)
                    ->where('users.is_partner','1')
                    ->where('users.chk_subscription','0')
                    ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
                    ->get(); 
                }
                 
            }
            
            

            return $subthemes_data;
        }
    }
