    public function saveweddingpackagesbp(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'name'=>'required',
                'email'=>'required|email',
                'phone_number'=>'required|digits:10', 
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {

                $customer = new Customer();
                $customer->name = $request->name;;
                $customer->email =$request->email;
                $customer->mobile = $request->phone_number;
                $customer->lead_source = 'Wedding Planner Package from Website';
                $customer->save();

                if($customer->save())    
                { 

                    if(!empty($request->teamid))
                    {
                        $teamid = $request->teamid;
                    }
                else
                    {
                        $teamid = NULL; 
                    }
            
                    $curtime = date("d-m-Y-h:i:s");

                    $wppackageform = new WppackagesForm();
                    
                    

                    $wppackageform->name = $request->name;
