    public function weddingpackagesbpform(Request $request)
        {
            if($request->ajax())
            {

                $rules = [
                    'name'=>'required',
                    'email'=>'required|email',
                    'phone_number'=>'required|digits:10',
                ];

                $validator = Validator::make($request->all(), $rules);

                if ($validator->fails())
                {
                    return response()->json([
                        'message' => $validator->messages(),
                    ]);
                }
                else
                {

                    if(!empty($request->teamid))
                    {
                        $teamid = $request->teamid;
                    }
                    else
                    {
                        $teamid = NULL;
                    }

                    $curtime = date("d-m-Y-h:i:s");

                    $leadTimeFormatted = now()->format('d/m/Y H:i');

                    $expiryDate = now()->addDay()->format('Y-m-d');

                    $curdate = date("d-m-Y");



                    /* =========================================
                    EXISTING PACKAGE CHECK
                    ========================================= */

                    $wppackageformmobile = $request->phone_number;

                    $wppackageformwppackage_id = $request->itemid;


                    $checkpackage = WppackagesForm::where('mobile',$wppackageformmobile)
                        ->where('wppackage_id',$wppackageformwppackage_id)
                        ->first();


                    /* =========================================
                    ONLY UPDATE OTP DETAIL
                    ========================================= */

                    if($checkpackage)
                    {
                        $checkpackage->otp_detail = "With OTP";

                        $checkpackage->save();
                    }



                    /* =========================================
                    PACKAGE DETAILS
                    ========================================= */

                    $plannerpackage = WpplannerPackage::select(
                            'id',
                            'user_id',
                            'mapped_city_name',
                            'mapped_state_name',
                            'package_type',
                            'this_pack_id'
                        )
                        ->where('id', $request->itemid)
                        ->first();


                    if($plannerpackage)
                    {

                        $plannerUser = User::select(
                                'id',
                                'chk_subscription',
                                'specialization'
                            )
                            ->where('id', $plannerpackage->user_id)
                            ->first();

                        $isFreePurchaseAllowed = false;



                        /* =========================================
                        SUBSCRIPTION CHECK
                        ========================================= */

                        if($plannerUser)
                        {

                            $subscription = DB::table('planners_subscription')
                                ->select(
                                    'subscriptoin_amount',
                                    'subscription_plan',
                                    'created_at'
                                )
                                ->where('user_id', $plannerUser->id)
                                ->latest()
                                ->first();

                            if($subscription)
                            {

                                $subAmount = $subscription->subscriptoin_amount ?? 0;

                                $subPlan = $subscription->subscription_plan ?? '';

                                $subscriptionStart = \Carbon\Carbon::parse(
                                    $subscription->created_at
                                )->startOfDay();

                                $today = now();


                                $monthDiff = $subscriptionStart->diffInMonths($today);

                                $monthStart = $subscriptionStart
                                    ->copy()
                                    ->addMonths($monthDiff)
                                    ->startOfDay();

                                if($monthStart->gt($today))
                                {
                                    $monthStart->subMonth();
                                }

                                $monthEnd = $monthStart
                                    ->copy()
                                    ->addMonth()
                                    ->subDay()
                                    ->endOfDay();


                                $yearDiff = $subscriptionStart->diffInYears($today);

                                $yearStart = $subscriptionStart
                                    ->copy()
                                    ->addYears($yearDiff)
                                    ->startOfDay();

                                if($yearStart->gt($today))
                                {
                                    $yearStart->subYear();
                                }

                                $yearEnd = $yearStart
                                    ->copy()
                                    ->addYear()
                                    ->subDay()
                                    ->endOfDay();


                                $dailyPurchases = DB::table('general_leads_buy')
                                    ->where('user_id', $plannerUser->id)
                                    ->whereDate('created_at', now())
                                    ->count();

                                $monthlyPurchases = DB::table('general_leads_buy')
                                    ->where('user_id', $plannerUser->id)
                                    ->whereBetween('created_at', [$monthStart, $monthEnd])
                                    ->count();

                                $yearlyPurchases = DB::table('general_leads_buy')
                                    ->where('user_id', $plannerUser->id)
                                    ->whereBetween('created_at', [$yearStart, $yearEnd])
                                    ->count();


                                if(
                                    $plannerUser->chk_subscription == 1 &&
                                    (
                                        ($subAmount == 9999 && $subPlan == 'legacy_full') ||
                                        ($subAmount == 4999 && $subPlan == 'legacy_full')
                                    )
                                )
                                {

                                    $limitExceeded =
                                        $dailyPurchases >= 3 ||
                                        $monthlyPurchases >= 30 ||
                                        $yearlyPurchases >= 360;

                                    if(!$limitExceeded)
                                    {
                                        $isFreePurchaseAllowed = true;
                                    }
                                }

                                elseif(
                                    $plannerUser->chk_subscription == 1 &&
                                    $subAmount == 4999 &&
                                    $subPlan == 'launch_4999_full'
                                )
                                {

                                    $limitExceeded =
                                        $dailyPurchases >= 3 ||
                                        $monthlyPurchases >= 10 ||
                                        $yearlyPurchases >= 120;

                                    if(!$limitExceeded)
                                    {
                                        $isFreePurchaseAllowed = true;
                                    }
                                }
                            }
                        }



                        /* =========================================
                        SAVE GENERAL LEAD
                        ========================================= */

                        $generallead = new GeneralLead();

                        $generallead->name = $request->name;

                        $generallead->email = $request->email;

                        $generallead->mobile = $request->phone_number;

                        $generallead->lead_time = $leadTimeFormatted;

                        $generallead->wedding_datefixed = $request->wedding_fix;

                        $generallead->approx_wedding = $request->wedding_fixapprox;

                        if(!empty($request->weddingdatefix))
                        {
                            $generallead->event_date = date(
                                "Y-m-d",
                                strtotime($request->weddingdatefix)
                            );
                        }

                        $generallead->expiry_date = $expiryDate;

                        $generallead->package_type = "wedding";

                        $generallead->event_category = "Package Lead";

                        $generallead->lead_type = "hot";

                        $generallead->price = 250;

                        $generallead->lead_description = $request->package_description1a;

                        $generallead->status = "not-purchased";

