                        $generallead->wppackage_id = $plannerpackage->id;

                        $generallead->wppackage_userid = $plannerpackage->user_id;

                        $generallead->wppackage_name = $plannerpackage->package_type;

                        $generallead->package_image1a = $request->package_image1a;

