                        $generallead->engagement_pax1a = $request->engagement_pax1a;

                        $generallead->lead_to_assign_detail = "Package Lead";

                        $generallead->this_user_id = $plannerpackage->user_id;

                        $generallead->not_show_wp = 1;

                        $generallead->lead_source = "Internal";

                        $generallead->lead_source_show = "PAW Lead";

                        $generallead->actual_lead_from = "Wedding packages - moved from WEBSITE";

                        $generallead->actual_lead_from_to_show = "Package Lead";

                        $generallead->save();



                        /* =========================================
                        AUTO FREE PURCHASE
                        ========================================= */

                        if($isFreePurchaseAllowed === true)
                        {

                            $purchaseTypeMap = [
                                'wedding' => 'wedding',
                                'photo&videographer' => 'photo&videographer',
                                'photo' => 'photo&videographer',
                                'catering' => 'catering',
                                'priests' => 'priest',
                                'priest' => 'priest',
                                'mehendi artist' => 'mehendi',
                                'mehendi' => 'mehendi',
                                'dj' => 'dj',
                                'venue' => 'venue'
                            ];

                            $userSpec = strtolower(
                                trim($plannerUser->specialization ?? '')
                            );

                            $purchaseType = $purchaseTypeMap[$userSpec]
                                ?? $plannerUser->specialization;


                            DB::table('general_leads_buy')->insert([

                                'general_leads_id' => $generallead->id,

                                'user_id' => $plannerUser->id,

                                'status' => 'purchased',

                                'created_at' => now(),

                                'updated_at' => now(),

                                'source' => 'paw_leads',

                                'purchase_type' => $purchaseType,

                                'price_purchase' => 'Free Purchase',

                            ]);
                        }



                        /* =========================================
                        FAST RESPONSE
                        ========================================= */

                        $response = response()->json([
                            'message' => 'Thank you for submitting your details. Our team will call you shortly',
                            'status' => '1',
                        ]);

                        $response->send();

                        if(function_exists('fastcgi_finish_request'))
                        {
                            fastcgi_finish_request();
                        }



                        /* =========================================
                        SEND PUSH NOTIFICATION
                        ========================================= */

                        $eventplanners = Userfcmtoken::select('fcm_token')
                            ->where('user_id', $plannerpackage->user_id)
                            ->get();

                        if($eventplanners->count() > 0)
                        {

                            $title = "New package lead is available for purchase";

                            $message = $request->name . " is looking for wedding planning services.";

                            $credentialsFilePath = Storage::path(
                                'firebase/wedding-planner-2ffbe-c7e9375595eb.json'
                            );

                            $clientFirebase = new Google_Client();

                            $clientFirebase->setAuthConfig($credentialsFilePath);

                            $clientFirebase->addScope(
                                'https://www.googleapis.com/auth/firebase.messaging'
                            );

                            $clientFirebase->refreshTokenWithAssertion();

                            $tokenFirebase = $clientFirebase->getAccessToken();

                            $access_token = $tokenFirebase['access_token'];

                            $projectId = "wedding-planner-2ffbe";

                            $url = "https://fcm.googleapis.com/v1/projects/{$projectId}/messages:send";

                            $headers = [
                                "Authorization: Bearer $access_token",
                                "Content-Type: application/json"
                            ];


                            foreach($eventplanners as $userToken)
                            {

                                if(empty($userToken->fcm_token))
                                {
                                    continue;
                                }

                                $postdata = [

                                    "message" => [

                                        "token" => $userToken->fcm_token,

                                        "notification" => [
                                            "title" => $title,
                                            "body" => $message,
                                        ],

                                        "data" => [
                                            "title" => (string)$title,
                                            "body" => (string)$message,
                                            "click_action" => "FLUTTER_NOTIFICATION_CLICK",
                                            "sound" => "default",
                                            "notification_type" => "package_lead"
                                        ],

                                        "android" => [
                                            "priority" => "high",
                                            "notification" => [
                                                "sound" => "default",
                                                "channel_id" => "default_channel"
                                            ]
                                        ],

                                        "apns" => [
                                            "payload" => [
                                                "aps" => [
                                                    "sound" => "default"
                                                ]
                                            ]
                                        ]
                                    ]
                                ];


                                $payload = json_encode($postdata);

                                $ch = curl_init();

                                curl_setopt($ch, CURLOPT_URL, $url);

                                curl_setopt($ch, CURLOPT_POST, true);

                                curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);

                                curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);

                                curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);

                                curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);

                                curl_setopt($ch, CURLOPT_TIMEOUT_MS, 700);

                                curl_setopt($ch, CURLOPT_NOSIGNAL, 1);

                                $result = curl_exec($ch);

                                if(curl_errno($ch))
                                {
                                    curl_close($ch);
                                    continue;
                                }

                                $responseFirebase = json_decode($result, true);

                                if(
                                    isset($responseFirebase['error']['details'][0]['errorCode']) &&
                                    $responseFirebase['error']['details'][0]['errorCode'] == 'UNREGISTERED'
                                )
                                {
                                    Userfcmtoken::where(
                                        'fcm_token',
                                        $userToken->fcm_token
                                    )->delete();
                                }

                                curl_close($ch);
                            }
                        }

                        exit;
                    }



                    return response()->json([
                        'message' => 'Thank you for submitting your details. Our team will call you shortly',
                        'status' => '1',
                    ]);
                }
            }
        }

