    public function cityselect(Request $request)
    {
        if(request()->ajax())
        {
            
            $statename = $request->statename;

            

            $setcity  =  
                CustomerCity::Join("customer_states","customer_cities.state_name_id","=","customer_states.id")
                ->where('customer_cities.active_status',1)
                ->where('customer_cities.state_name_id',$statename)  
                ->distinct()->orderBy('customer_cities.district_name','asc')->get();
  
                $resultString['status'] = 1; 
                $resultString['setcity'] = $setcity;
                return json_encode($resultString);
        }

        else 
        {
                $resultString['status'] = 0; 
                $resultString['setcity'] = "";
                return json_encode($resultString);
        }
    }

    public function saveloanemiregister(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'name'=>'required',
                'last_name'=>'required',
                'gender'=>'required',
                'dob'=>'required',
                'email'=>'required|email',
                'phone'=>'required|digits:10',
                'employment_type'=>'required',
                'monthly_salary'=>'required',
                'loan_amt'=>'required',
                'loan_city'=>'required',
                'residential_pincode'=>'required',
                'pan'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {

                $curdate = date("d-m-Y h:i:s");

                $dob = $request->dob;

                $dobsplit = explode("-",$dob);

                $day = $dobsplit[0];
                $month = $dobsplit[1];
                $year = $dobsplit[2];

                $data = new LoanEmi();
                
                $data->first_name = $request->name;
                $data->last_name = $request->last_name;
                $data->gender = $request->gender;
                $data->full_dob = $request->dob;
                $data->day_dob = $day;
                $data->month_dob = $month;
                $data->year_dob = $year;
                $data->mobile = $request->phone;
                $data->email = $request->email;
                $data->employment_type = $request->employment_type;
                $data->monthly_salary = $request->monthly_salary;
                $data->loan_amount_required = $request->loan_amt;
                $data->city = $request->loan_city;
                $data->resedential_pincode = $request->residential_pincode;
                $data->PAN = $request->pan;
                $data->requested_date = $curdate; 

                
                if($data->save())
                { 
                     
                    return response()->json([
                        /*'message' => 'Thank you for submitting your details. Our team will call you shortly',*/
                        'message' => '',
                        'status' => '1',
                    ]);
                    
                }
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }	
    
