    public function saveresponseformpackage(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'popname'=>'required', 
                'popemail'=>'required',
                'popmobile'=>'required|digits:10',
                'weddingcitypopup'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {

                $today = date('d/m/y h:i:s');

                $leadform = new ChatLeadform();
                

                
                $leadform->enquiryfor = "Wedding Package Page"; 
                $leadform->role_name = "Website Enquiry";

                $leadform->name = $request->popname;
                $leadform->mobile = $request->popmobile; 
                $leadform->email = $request->popemail;
                $leadform->city = $request->weddingcitypopup;

                $leadform->wedding_fixed = $request->wedding_fix;
                $leadform->wedding_date = $request->weddingdatepopup;
                $leadform->approx_wedding = $request->wedding_fixapprox;



                $leadform->otp_list = "Without OTP";
                 
                $leadform->enquired_time = $today;
                
                $leadform->websitie_source = "Web Wedding Package Page";

                $leadform->website_from = "Web Wedding Package Page";

                if($leadform->save())
                {
                    
                    /*$mailstatus = Mail::to($request->email)->cc(['enquiry@planawedding.in'])->send(new AdFormMail($data));*/
                    
                    return response()->json([
                        /*'message' => 'Thank you for submitting your details. Our team will call you shortly',*/
                        'message' => '',
                        'status' => '1',
                    ]);
                    
                }
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }	



    public function saveresponseformeditpackage(Request $request)
    {
        if($request->ajax())
        {
            $rules = [
                'popname'=>'required', 
                'popemail'=>'required',
                'popmobile'=>'required|digits:10',
                'weddingcitypopup'=>'required',
            ];
            
            $validator = Validator::make($request->all(), $rules);
            
            if ($validator->fails()) 
            {
                // Validation failed
                return response()->json([
                    'message' => $validator->messages(),
                ]);
            } 
            else 
            {

                $today = date('d/m/y h:i:s');

                
                
                $userexist = ChatLeadform::where('email', '=', $request->popemail)->where('name',$request->popname)->latest()->first();

                 

                if (!empty($userexist))

                {

                    $userexist->enquiryfor = "Wedding Package Page"; 
                    $userexist->role_name = "Website Enquiry";

                    $userexist->mobile = $request->popmobile;
                    $userexist->city = $request->weddingcitypopup;

                    $userexist->wedding_fixed = $request->wedding_fix;
                    $userexist->wedding_date = $request->weddingdatepopup;
                    $userexist->approx_wedding = $request->wedding_fixapprox;



                    $userexist->otp_list = "Without OTP";
                    
                    $userexist->enquired_time = $today;
                    
                    $userexist->websitie_source = "Wedding Package Page";

                    $userexist->website_from = "Wedding Package Page";

                    if($userexist->save())
                    {
                        
                        return response()->json([  
                            'message' => '',
                            'status' => '1',
                        ]);
                        
                    }
                    else
                    {
                        return response()->json([
                            'message' => 'Error while adding. Check the item and try again.',
                            'status' => '0',
                        ]);
                    } 

                }
                 
                else
                {
                    return response()->json([
                        'message' => 'Error while adding. Check the item and try again.',
                        'status' => '0',
                    ]);
                }
            }
        }
    }


