                    ->where('weddingplanner_packages.package_type',$packagename)
                    ->where('weddingplanner_packages.wedding_pax',$destimuhurat_paxname)
                    ->where('weddingplanner_packages.reception_pax',$destireception_paxname)
                    ->where('weddingplanner_packages.enable_package','1')
                    ->where('weddingplanner_packages.active_disable',0) 
                    ->distinct()->orderBy('weddingplanner_packages.package_amount','asc')->get();
