        if(request()->ajax())
        {
            $themeid = $request->itemid;

            if(!empty($themeid))
                {
                    $themes = VenueList::where('id',$themeid)->where('show_web','1') 
                    ->latest()->first();
 
                    return response()->json([
                        'message' => $themes,
                        'status' => '1',
                    ]);
                }

            else 
                {
                    return response()->json([
                        'message' => '',
                        'status' => '0',
                    ]);
                }
        }
    }

  
    public function saveweddingvenues(Request $request)
        {
            if($request->ajax())
                {
                    $rules = [
                        'name'=>'required',
                        'email'=>'required|email',
                        'phone_number'=>'required|digits:10', 
                    ];
                    
                    $validator = Validator::make($request->all(), $rules);
                    
                    if ($validator->fails()) 
                        {
                            // Validation failed
                            return response()->json([
                                'message' => $validator->messages(),
                            ]);
                        } 
                    else 
                        {
                            $customer = new Customer();
                            $customer->name = $request->name;
                            $customer->email =$request->email;
                            $customer->mobile = $request->phone_number;
