                                    $venueenquiry->name = $request->name;
                                    $venueenquiry->email = $request->email;
                                    $venueenquiry->mobile = $request->phone_number;
                                    $venueenquiry->wedding_fixed = $request->wedding_fix;
                                    $venueenquiry->wedding_date = $request->weddingdatefix;
                                    $venueenquiry->wedding_approx = $request->wedding_fixapprox; 
                                    $venueenquiry->venue_actual_id = $request->itemid;
                                    $venueenquiry->venue_venueid = $request->packageidnew_1a;
                                    $venueenquiry->venue_userid = $request->userid; 
                                    $venueenquiry->requested_on = $curtime;


                                     if($venueenquiry->save())
                                        {
 

                                            $plannerid= "43";

                                            $eventplanner = User::findOrFail($plannerid);

                                            $eventplanners = Userfcmtoken::whereIn('user_id', $eventplanner)->get();

                                            if($eventplanners)
                                                {

                                                    $projectId = config('services.fcm.wedding-planner-2ffbe'); # INSERT COPIED PROJECT ID

                                                    $credentialsFilePath = Storage::path('firebase/wedding-planner-2ffbe-c7e9375595eb.json');
                                                        
                                                    $client = new Google_Client();
                                                    $client->setAuthConfig($credentialsFilePath);
                                                    $client->addScope('https://www.googleapis.com/auth/firebase.messaging');
                                                    $client->refreshTokenWithAssertion();
                                                    $token = $client->getAccessToken();

                                                    $access_token = $token['access_token'];


                                                    $projectId= "wedding-planner-2ffbe";
                                                    $url = "https://fcm.googleapis.com/v1/projects/{$projectId}/messages:send"; 

                                                    $headers =array("Authorization: Bearer $access_token",
                                                        "content-type: application/json"
                                                    );  

                                                        
                                                    //$title = "New lead is assigned";
                                                    $title = "New Venue Enquiry from Web - Check Admin Dashboard";
                                                    $message = "Dear Team New Venue enquiry from web by $name has been requested.";   
                                                    

                                                    foreach($eventplanners as $user) 
                                                    {
                                                        $tokens = "";
                                                        
                                                       
                                                        
                                                        $postdata = [
                                                            "message" => [
                                                            "token" => $user['fcm_token'],
                                                            "notification" => [
                                                                "title" => $title,
                                                                "body" => $message, 
                                                                ],
                                                            "data" => [
                                                                "title" => $title,
                                                                "body" => $message,  
                                                                "click_action" => "FLUTTER_NOTIFICATION_CLICK", 
                                                                ],
                                                            
                                                            ]
                                                        ];
                                                        $payload = json_encode($postdata);  
                                                        
                                                        $ch = curl_init();
                                                        $timeout = 120;
                                                        curl_setopt($ch, CURLOPT_URL, $url);
                                                        curl_setopt($ch, CURLOPT_RETURNTRANSFER, 1);
                                                        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, $timeout);
                                                        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "POST");
                                                        curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);
                                                        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
                                                    
                                                        // Get URL content
                                                        $result = curl_exec($ch);    
                                                        
                                                        curl_close($ch);
                                                    } 
                                                }



                                            return response()->json([
