                                                'message' => 'Check your connection',
                                                'status' => '0',
                                            ]);
                                        }

                                }
                            else 
                                {
                                    return response()->json([
                                        'message' => 'Customer not Saved',
                                        'status' => '0',
                                    ]);
                                }
                        }
                }
        }



    public function getweddingvenuespotp(Request $request)
        {
            if($request->ajax())
            {
                $name = urldecode($request->name);
                $email = urldecode($request->email);
                $mobile = $request->mobile;
                
                $opt_input = rand(1000,9999);
                $request->session()->put('opt_input', $opt_input);

                
                
                $message = "$opt_input is your OTP from Plan a wedding -Variety Vintage Technologies Pvt Ltd";
                $message = urlencode($message); 
                $ch=curl_init();
                curl_setopt($ch,CURLOPT_URL,"https://smsapi.24x7sms.com/api_2.0/SendSMS.aspx?APIKEY=4AbdiHVSDzt&MobileNo=".$mobile."&SenderID=planaw&Message=".$message."&ServiceName=TEMPLATE_BASED");
                curl_setopt($ch,CURLOPT_RETURNTRANSFER, TRUE);
                $output =curl_exec($ch);
                curl_close($ch);

                if (!empty($opt_input))
                {
                    $resultString['status'] = 1;
                    $resultString['opt_input'] = $opt_input;
                    echo(json_encode($resultString));
                }
                else
                {
                    $resultString['status'] = 2;
                    $resultString['opt_input'] = $opt_input;
                    echo(json_encode($resultString));
                }
            }
        }


