    public function getvenuestate(Request $request)     
        {
            if(request()->ajax())
                {

                    $statename = $request->statename;


                    $setpackages  =
                    VenueList::select('venue_lists.location_display')
                    ->Join("users","venue_lists.user_id","=","users.id")
                    /*->where('users.wallet_amount','>=',500) */
                    ->where('users.is_active',1)
                    ->where('users.role_id',4)
                    ->where('users.display_venue_web','yes')
                    ->where('venue_lists.mapped_state_name',$statename)
                    //->where('weddingplanner_packages.enable_package','1')
                    //->where('weddingplanner_packages.active_disable',0) 
                   // ->where('users.wallet_amount','>',500)
                   ->where(function ($query) {
                        $query->where('venue_lists.show_web',1);
                    })
                    ->distinct()->orderBy('venue_lists.location_display','asc')->get();
        
                    
                    $resultString['status'] = 1;
                    $resultString['packagesset'] = $setpackages;
                    return json_encode($resultString);
                }
        }


