    public function getlistedpackagecities(Request $request)
        {
            if(request()->ajax())
            {
                $itemid = $request->itemid;
                $themename = $request->themename;
    
                $setpackagetype  =  
                    WpplannerPackage::select('weddingplanner_packages.mapped_city_name')
                    ->Join("cities_packages","weddingplanner_packages.map_city","=","cities_packages.id")
                    ->where('cities_packages.city_active',1)
                    ->Join("users","weddingplanner_packages.user_id","=","users.id") 
                    ->where('users.is_active',1) 
                    ->where('users.chk_subscription','1')
                    /* ->where('users.wallet_amount','>=',500)
                    
                    ->Join("users","weddingplanner_packages.user_id","=","users.id")
                    ->where('users.wallet_amount','>=',500) 
                    ->where('users.is_active',1)
                    ->where('users.role_id',4)
                    */
                    ->where('weddingplanner_packages.mapped_state_name',$themename) 
                    ->where(function ($query) {
                        $query->where('weddingplanner_packages.active_disable',0)
                        ->where('weddingplanner_packages.enable_package','1')
                        ->where('users.display_wedding_package',"yes");
                    })
                   // ->where('users.wallet_amount','>',500)
                    ->distinct()->orderBy('weddingplanner_packages.mapped_city_name','asc')->get();
    
    
    
                    $resultString['status'] = 1; 
                    $resultString['setpackagetype'] = $setpackagetype;
                    return json_encode($resultString);
            }
        }

