                $cart_items = $request->session()->get('weddingcart');
            }

            foreach($theme_names1 as $theme)
            {
                $subthemes_array[] = $theme->id;
            }
            
            $subthemes_data = Subtheme::withCount('subthemeimages')->whereIn('theme_id',$subthemes_array)->where('user_id','43')
            ->orderBy('id','desc')
            
            ->get();
            
            $subthemes_data = $subthemes_data->whereIn('theme_id',$subthemes_array);
                    
            $muhuratpack_pax  = WpplannerPackage::select('wedding_pax')->where('package_type','Muhurat Package')->where('enable_package','1')->where('active_disable',0)->distinct()->orderBy('wedding_pax','asc')->get();
        
            $muhuratpack_price  = WpplannerPackage::select('package_amount')->where('package_type','Muhurat Package')->where('enable_package','1')->where('active_disable',0)->distinct()->orderBy('package_amount','asc')->get();
        
            $receptionpack_pax  = WpplannerPackage::select('reception_pax')->where('package_type','Reception Package')->where('enable_package','1')->where('active_disable',0)->distinct()->orderBy('reception_pax','asc')->get();
            
            $receptionpack_price  =  WpplannerPackage::select('package_amount')->where('package_type','Reception Package')->where('enable_package','1')->where('active_disable',0)->distinct()->orderBy('package_amount','asc')->get();


            $muhuratreceppack_pax1  = WpplannerPackage::select('wedding_pax')->where('package_type','Muhurat & Reception Package')->where('enable_package','1')->where('active_disable',0)->distinct()->orderBy('wedding_pax','asc')->get();
        
