    public function weddingpackenewuiitems(Request $request)
    {
        // Get cities as array
        $subthemes_array = explode(',', $request->input('subthemes_array', ''));

        $subthemes_data = User::where('role_id', 4)
            ->where('is_active', 1)
            ->join("weddingplanner_packages", "users.id", "=", "weddingplanner_packages.user_id")
            //->whereIn('weddingplanner_packages.package_city', $subthemes_array)
            ->where(function ($query) {
                $query->where('weddingplanner_packages.active_disable', 0)
                    ->where('weddingplanner_packages.enable_package', '1')
                    ->where('users.display_wedding_package', "yes");
            })
            ->orderByRaw('CONVERT(weddingplanner_packages.package_amount, SIGNED) asc')
            ->select(
                'weddingplanner_packages.id as packageid',
                'weddingplanner_packages.package_type as title',
                'weddingplanner_packages.package_amount as price',
                'weddingplanner_packages.wedding_pax as guests',
                'weddingplanner_packages.mapped_city_name as city',
                'weddingplanner_packages.mapped_state_name as state',
                'weddingplanner_packages.package_type as type',
                'weddingplanner_packages.additonal_remarks as feature_title',
                'weddingplanner_packages.package_description as feature_description',
                'weddingplanner_packages.package_description as description',
                'weddingplanner_packages.package_image as package_image',
                'weddingplanner_packages.final_discount as final_discount'
            )
            ->get();

        return response()->json($subthemes_data);
    }



