        public function weddingpackagesbpformseparate(Request $request)
            {
                if($request->ajax())
                    {
                        $rules = [
                            'name'=>'required',
                            'email'=>'required|email',
                            'phone_number'=>'required|digits:10', 
                        ];
                        
                        $validator = Validator::make($request->all(), $rules);
                        
