    public function weddingcourse()
    {
        $allthemes = $this->allthemes();
        
        $theme_names = $allthemes[0];
        $theme_names1 = $allthemes[1];
		$theme_names2 = $allthemes[2];
		$theme_names3 = $allthemes[3];
		
        $homesliders = Homeslider::latest()->get();
        $coupon_texts = Coupontext::where('trans_type','general')->get();
        $coupon_texts = $coupon_texts->toArray();

        return view('website.weddingcourse',compact(['coupon_texts','homesliders','theme_names','theme_names1','theme_names2','theme_names3']));
    }
    


    public function savenewwcourse(Request $request)
        {
            if($request->ajax())
            {
                $rules = [
                    'name'=>'required',
                    'email'=>'required|email',
                    'phone_number'=>'required|digits:10',
                    'city'=>'required', 
                    'slot'=>'required', 
                ];
                
                $validator = Validator::make($request->all(), $rules);
                
                if ($validator->fails()) 
                {
                    // Validation failed
                    return response()->json([
                        'message' => $validator->messages(),
                    ]);
                } 
                else 
                {
                    $weddingcourse = new WeddingCourses();
                    
                    $weddingcourse->name = $request->name;
                    $weddingcourse->email = $request->email;
                    $weddingcourse->phone_number = $request->phone_number;
                    
                    $weddingcourse->city = $request->city;
                    
                    $weddingcourse->lookingfor = $request->slot;
                    
                    if($weddingcourse->save())
                    {


                        $chatleadform = new ChatLeadform();
                        $chatleadform->enquiryfor = "Wedding Course";
                        $chatleadform->role_name = "Wedding Course";
                        $chatleadform->role_id = "11";
                        $chatleadform->name = $request->name; 
                        $chatleadform->email = $request->email;
                        $chatleadform->mobile = $request->phone_number;
                        $chatleadform->otp_list = "Without OTP"; 
                        $chatleadform->city = $request->city;     
                        $chatleadform->website_from = "Wedding Course Web Page - " . $request->slot;

                        $chatleadform->websitie_source = "Wedding Course Web Page - " . $request->slot;

                        $chatleadform->enquired_time = date('d/m/Y H:i:s');

                        $chatleadform->save();

                        $data = array('name' => $request->name, 'email' => $request->email, 'mobile' => $request->phone_number, 'city' => $request->city, 'lookingfor' => $request->lookingfor);
                    
                        /*$mailstatus = Mail::to($request->email)->cc(['enquiry@planawedding.in'])->send(new AdFormMail($data));*/
                        
                        return response()->json([
                            /*'message' => 'Thank you for submitting your details. Our team will call you shortly',*/
                            'message' => '',
                            'status' => '1',
                        ]);
                        
                    }
                    else
                    {
                        return response()->json([
                            'message' => 'Error while adding. Check the item and try again.',
                            'status' => '0',
                        ]);
                    }
                }
            }
        }

