        public function getCoupleQuestions_1($type, Request $request)
        {
            $session_id = $request->get('session_id'); // read from ?session=
            $session = DB::table('couple_assessments')->where('session_id', $session_id)->first();

            if (!$session) {
                return response()->json(['success' => false, 'message' => 'Invalid session ID']);
            }

            // If no stored order, shuffle once and save
            if (empty($session->question_order)) {
                $questions = DB::table('couple_questions')
                    ->where('assessment_type', $type)
                    ->where('is_active', 1)
                    ->pluck('id')
                    ->shuffle()
                    ->values()
                    ->toArray();

                DB::table('couple_assessments')
                    ->where('session_id', $session_id)
                    ->update(['question_order' => json_encode($questions)]);
            } else {
                $questions = json_decode($session->question_order, true);
            }

            // Fetch questions in that exact order
            $ordered = DB::table('couple_questions')
                ->whereIn('id', $questions)
                ->get()
                ->map(function ($q) {
                    $q->options = json_decode($q->options);
                    return $q;
                });

            // Maintain same order
            $sorted = collect($questions)->map(function ($id) use ($ordered) {
                return $ordered->firstWhere('id', $id);
            });

            return response()->json([
                'success' => true,
                'questions' => $sorted->values(),
            ]);
        }

