        public function getCoupleQuestions_3($type, Request $request)
            {
                $session_id = $request->get('session_id'); // ?session=
                $session = DB::table('couple_assessments')->where('session_id', $session_id)->first();

                if (!$session) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Invalid session ID',
                    ]);
                }

                // 🧠 1. Define "free" categories (5 total, 2 from Communication)
                $freeCategories = [
                    'Communication',
                    'Trust & Security',
                    'Emotional Support',
                    'Family & Social',
                    'Future Planning'
                ];

                // 🧠 2. Select questions based on assessment type
                if ($type === 'free') {
                    // If this couple has no saved question order → create a new random one
                    if (empty($session->question_order)) {
                        $questions = collect();

                        foreach ($freeCategories as $cat) {
                            $q = DB::table('couple_questions')
                                ->where('category', $cat)
                                ->where('assessment_type', 'free')
                                ->where('is_active', 1)
                                ->inRandomOrder()
                                ->first();

                            if ($q) {
                                $questions->push($q);
                            }
                        }

                        // Shuffle the selected 5 randomly — different per couple
                        $questions = $questions->shuffle();

                        // Save question order for this session
                        DB::table('couple_assessments')
                            ->where('session_id', $session_id)
                            ->update(['question_order' => json_encode($questions->pluck('id')->toArray())]);
                    } else {
                        // Load the saved question IDs for this couple
                        $questionIds = json_decode($session->question_order, true);
                        $questions = DB::table('couple_questions')
                            ->whereIn('id', $questionIds)
                            ->get();
                    }
                } else {
                    // 🧩 For premium or other types — load all active questions
                    if (empty($session->question_order)) {
                        $allQuestions = DB::table('couple_questions')
                            ->where('assessment_type', $type)
                            ->where('is_active', 1)
                            ->inRandomOrder()
                            ->get();

                        DB::table('couple_assessments')
                            ->where('session_id', $session_id)
                            ->update(['question_order' => json_encode($allQuestions->pluck('id')->toArray())]);

                        $questions = $allQuestions;
                    } else {
                        $questionIds = json_decode($session->question_order, true);
                        $questions = DB::table('couple_questions')
                            ->whereIn('id', $questionIds)
                            ->get();
                    }
                }

                // 🧠 3. Decode options JSON
                $questions = $questions->map(function ($q) {
                    $q->options = json_decode($q->options, true);
                    return $q;
                });

                // 🧠 4. Shuffle order for this *user* (each partner sees their own random sequence)
                $questions = $questions->shuffle()->values();

                // ✅ 5. Return final list
                return response()->json([
                    'success' => true,
                    'questions' => $questions,
                ]);
            }


