        public function saveCoupleAnswer_1(Request $request)
            {
                $request->validate([
                    'session_id' => 'required|string',
                    'question_id' => 'required|integer',
                    'answer_text' => 'required|string',
                    'answered_by' => 'required|in:bride,groom',
                    'assessment_type' => 'nullable|string',
                ]);

                // 🔹 Find the couple record based on session_id
                $couple = DB::table('couple_assessments')
                    ->select('id')
                    ->where('session_id', $request->session_id)
                    ->first();

                if (!$couple) {
                    return response()->json(['success' => false, 'message' => 'Invalid couple session ID']);
                }

                // 🔹 Save or update the answer
                DB::table('couple_answers')->updateOrInsert(
                    [
                        'session_id'   => $request->session_id,
                        'question_id'  => $request->question_id,
                        'answered_by'  => $request->answered_by,
                    ],
                    [
                        'couple_id'        => $couple->id,
                        'answer_text'      => $request->answer_text,
                        'assessment_type'  => $request->assessment_type ?? 'free',
                        'updated_at'       => now(),
                    ]
                );

                return response()->json(['success' => true, 'message' => 'Answer saved successfully']);
            }

