        public function checkCoupleResults_1($sessionId)
            {
                $couple = DB::table('couple_assessments')->where('session_id', $sessionId)->first();

                if (!$couple) {
                    return response()->json(['success' => false, 'message' => 'Invalid session ID']);
                }

                // Get total number of questions for this assessment type
                $totalQuestions = DB::table('couple_questions')
                    ->where('assessment_type', $couple->assessment_type)
                    ->where('is_active', 1)
                    ->count();

                // Fetch answers grouped by who answered
                $answers = DB::table('couple_answers')
                    ->select('answered_by', DB::raw('COUNT(DISTINCT question_id) as answered_count'))
                    ->where('session_id', $sessionId)
                    ->groupBy('answered_by')
                    ->get()
                    ->pluck('answered_count', 'answered_by')
                    ->toArray();

                $brideAnswered = $answers['bride'] ?? 0;
                $groomAnswered = $answers['groom'] ?? 0;

                $brideDone = $brideAnswered >= $totalQuestions && $totalQuestions > 0;
                $groomDone = $groomAnswered >= $totalQuestions && $totalQuestions > 0;

                // ✅ Both completed all questions
                if ($brideDone && $groomDone) {
                    return response()->json([
                        'success' => true,
                        'completed' => true,
