        public function generateCoupleResults_1($session_id)
            {
                $session = \App\CoupleAssessment::where('session_id', $session_id)->first();

                if (!$session) {
                    return response()->json(['success' => false, 'message' => 'Invalid session.']);
                }

                // ✅ If result link already exists, just reuse it
                if (!empty($session->result_link)) {
                    return response()->json([
                        'success' => true,
                        'reuse' => true,
                        'session_id' => $session_id,
                        'bride_name' => $session->bride_name,
                        'groom_name' => $session->groom_name,
                        'result_link' => $session->result_link,
                        'message' => 'Results already exist. Redirecting to saved results.'
                    ]);
                }

                $questions = \App\CoupleQuestion::where('is_active', 1)->get();
                $totalQuestions = $questions->count();

                $brideAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'bride')
                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'groom')
                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                if (count($brideAnswers) < $totalQuestions || count($groomAnswers) < $totalQuestions) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Both partners must complete all questions before generating results.'
                    ]);
                }

                // ✅ Calculate compatibility
                $matchCount = 0;
                $categoryScores = [];
                $categoryCounts = [];

                foreach ($questions as $q) {
                    $qid = $q->id;
                    $cat = $q->category;
                    if (!isset($categoryScores[$cat])) {
                        $categoryScores[$cat] = 0;
                        $categoryCounts[$cat] = 0;
                    }

                    if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {
                        $categoryCounts[$cat]++;
                        $score = ($brideAnswers[$qid] === $groomAnswers[$qid]) ? 100 : 60;
                        $categoryScores[$cat] += $score;
                        if ($score === 100) $matchCount++;
                    }
                }

                $categories = [];
                foreach ($categoryScores as $cat => $score) {
                    $categories[$cat] = round($score / $categoryCounts[$cat]);
                }

                $compatibilityScore = round(($matchCount / $totalQuestions) * 100);

                // ✅ Create permanent result link
                $resultLink = url('/couplevibe?results=' . $session_id);

                // ✅ Save it once
                $session->update([
                    'result_link' => $resultLink,
                    'status' => 'completed'
                ]);

                return response()->json([
                    'success' => true,
                    'reuse' => false,
                    'session_id' => $session_id,
                    'bride_name' => $session->bride_name,
                    'groom_name' => $session->groom_name,
                    'assessment_type' => $session->assessment_type,
                    'compatibility_score' => $compatibilityScore,
                    'categories' => $categories,
                    'result_link' => $resultLink,
                    'message' => 'Results generated successfully.'
                ]);
            }

        public function generateCoupleResults($session_id)
            {
                $session = \App\CoupleAssessment::where('session_id', $session_id)->first();

                if (!$session) {
                    return response()->json(['success' => false, 'message' => 'Invalid session.']);
                }

                // Reuse existing results
                if (!empty($session->result_link)) {
                    return response()->json([
                        'success' => true,
                        'reuse' => true,
                        'session_id' => $session_id,
                        'bride_name' => $session->bride_name,
                        'groom_name' => $session->groom_name,
                        'assessment_type' => $session->assessment_type,
                        'result_link' => $session->result_link
                    ]);
                }

                // Fetch questions used in this session (5 or 20)
                $questionOrder = json_decode($session->question_order, true) ?? [];

                $questions = \App\CoupleQuestion::whereIn('id', $questionOrder)->get();
                $totalQuestions = count($questionOrder);

                // Fetch numeric value answers
                $brideAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'bride')
                    ->pluck('answer_value', 'question_id')
                    ->toArray();

                $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'groom')
                    ->pluck('answer_value', 'question_id')
                    ->toArray();

                // Ensure both completed
                if (count($brideAnswers) < $totalQuestions || count($groomAnswers) < $totalQuestions) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Both partners must complete all questions.'
                    ]);
                }

                // ------------------------------
                // ⭐ Correct Category Scoring
                // ------------------------------

                $categoryScores = [];
                $categoryCounts = [];

                foreach ($questions as $q) {
                    $qid = $q->id;
                    $cat = $q->category;

                    if (!isset($categoryScores[$cat])) {
                        $categoryScores[$cat] = 0;
                        $categoryCounts[$cat] = 0;
                    }

                    if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {

                        $b = (int)$brideAnswers[$qid];  // 1–4
                        $g = (int)$groomAnswers[$qid];  // 1–4

                        // ❗ Convert difference to score 0–100%
                        // diff 0 = 100%
                        // diff 1 = 75%
                        // diff 2 = 50%
                        // diff 3 = 25%
                        // diff 4 = 0%
                        $diff = abs($b - g);
                        $score = max(0, 100 - ($diff * 25));

                        $categoryScores[$cat] += $score;
                        $categoryCounts[$cat]++;
                    }
                }

                // Final category scores
                $categories = [];
                foreach ($categoryScores as $cat => $score) {
                    $categories[$cat] = round($score / $categoryCounts[$cat]); // always 0–100
                }

                // ------------------------------
                // ⭐ Overall Compatibility Score (0–100)
                // ------------------------------
                $totalScore = array_sum($categories);
                $compatibilityScore = round($totalScore / count($categories));

                // ------------------------------
                // ⭐ Save Result Link
                // ------------------------------
                $resultLink = url('/couplevibe?results=' . $session_id);

                $session->update([
                    'result_link' => $resultLink,
                    'status' => 'completed'
                ]);

                return response()->json([
                    'success' => true,
                    'reuse' => false,
                    'session_id' => $session_id,
                    'bride_name' => $session->bride_name,
                    'groom_name' => $session->groom_name,
                    'assessment_type' => $session->assessment_type,
                    'compatibility_score' => $compatibilityScore,
                    'categories' => $categories,
                    'result_link' => $resultLink
                ]);
            }


