        public function generateCoupleResultLink(Request $request)
            {
                try {
                    $sessionId = $request->session_id ?? null;
                    $coupleId  = $request->couple_id ?? null;

                    // ✅ Fetch record either by id or session_id
                    $query = \App\CoupleAssessment::query();

                    if ($coupleId) {
                        $query->where('id', $coupleId);
                    } elseif ($sessionId) {
                        $query->where('session_id', $sessionId);
                    } else {
                        return response()->json([
                            'success' => false,
                            'message' => 'Missing couple_id or session_id.'
                        ], 400);
                    }

                    $couple = $query->first();

                    if (!$couple) {
                        return response()->json([
                            'success' => false,
                            'message' => 'Couple assessment not found.'
                        ], 404);
                    }

                    // ✅ If link already exists, return the same one
                    if (!empty($couple->result_link)) {
                        return response()->json([
                            'success' => true,
                            'existing' => true,
                            'result_link' => $couple->result_link,
                            'message' => 'Existing result link found.'
                        ]);
                    }

                    // ✅ Generate result link if not present
                    $resultLink = url('/couplevibe?results=' . $couple->session_id);

                    $couple->result_link = $resultLink;
                    $couple->save();

                    return response()->json([
                        'success' => true,
                        'existing' => false,
                        'result_link' => $resultLink,
                        'message' => 'New result link generated and saved successfully.'
                    ]);

                } catch (\Exception $e) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Error generating result link.',
                        'error' => $e->getMessage()
                    ], 500);
                }
            }
          
