        public function viewCoupleResults_2($session_id)
            {
                try {
                    // 🔹 Try fetching the assessment record
                    $session = \App\CoupleAssessment::where('session_id', $session_id)->first();

                    if (!$session) {
                        Log::warning("⚠️ No record found for session_id: {$session_id}");
                        return response()->json(['success' => false, 'message' => 'Result not found.']);
                    }

                    // 🔹 Fetch all questions and answers
                    $questions = \App\CoupleQuestion::where('is_active', 1)->get();
                    $totalQuestions = $questions->count();

                    $brideAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                        ->where('answered_by', 'bride')
                        ->pluck('answer_text', 'question_id')
                        ->toArray();

                    $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                        ->where('answered_by', 'groom')
                        ->pluck('answer_text', 'question_id')
                        ->toArray();

                    // 🔹 Calculate category-wise scores
                    $matchCount = 0;
                    $categoryScores = [];
                    $categoryCounts = [];

                    foreach ($questions as $q) {
                        $qid = $q->id;
                        $cat = $q->category;
                        if (!isset($categoryScores[$cat])) {
                            $categoryScores[$cat] = 0;
                            $categoryCounts[$cat] = 0;
                        }

                        if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {
                            $categoryCounts[$cat]++;
                            $score = ($brideAnswers[$qid] === $groomAnswers[$qid]) ? 100 : 60;
                            $categoryScores[$cat] += $score;
                            if ($score === 100) $matchCount++;
                        }
                    }

                    $categories = [];
                    foreach ($categoryScores as $cat => $score) {
                        $categories[$cat] = round($score / max(1, $categoryCounts[$cat]));
                    }

                    $compatibilityScore = $totalQuestions > 0
                        ? round(($matchCount / $totalQuestions) * 100)
                        : 0;

                    // 🔹 Generate PDF only if not already saved
                    if (empty($session->pdf_link)) {
                        Log::info("🧾 Generating PDF for session: {$session_id}");

