                                    .section { margin-bottom:25px; }
                                    .score { font-size:24px; color:#27ae60; text-align:center; }
                                    .category { padding:8px 12px; border-bottom:1px solid #ddd; }
                                    .footer { margin-top:40px; text-align:center; font-size:12px; color:#777; }
                                </style>
                            </head>
                            <body>
                                <div class="title">💖 Compatibility Report</div>
                                <div class="section">
                                    <strong>Couple:</strong> ' . e($session->bride_name) . ' & ' . e($session->groom_name) . '<br>
                                    <strong>Assessment Type:</strong> ' . e($session->assessment_type) . '
                                </div>
                                <div class="section score">
                                    Compatibility Score: ' . $compatibilityScore . '%
                                </div>
                                <div class="section">
                                    <h3>Category Breakdown</h3>';
                                    foreach ($categories as $cat => $score) {
                                        $html .= '<div class="category"><strong>' . e(ucwords(str_replace('_', ' ', $cat))) . ':</strong> ' . $score . '%</div>';
                                    }
                                    $html .= '
                                </div>
                                <div class="footer">
                                    Generated automatically by Plan A Wedding Compatibility Tool
                                </div>
                            </body>
                        </html>';

                        // 🔹 Generate & store the PDF
                        $pdf = PDF::loadHTML($html)->setPaper('a4', 'portrait');
                        Storage::disk('public')->put($pdfPath, $pdf->output());

                        // 🔹 Save PDF path in DB
                        $session->pdf_link = $pdfPath;
                        $session->save();

                        DB::table('couple_assessments')
                            ->where('id', $session->id)
                            ->update(['pdf_link' => $pdfPath]);

                        Log::info("✅ PDF generated and saved: {$pdfPath}");
                    }

                    // 🔹 Return JSON response
                    return response()->json([
                        'success' => true,
                        'session_id' => $session_id,
                        'bride_name' => $session->bride_name,
                        'groom_name' => $session->groom_name,
                        'compatibility_score' => $compatibilityScore,
                        'categories' => $categories,
                        'result_link' => $session->result_link,
                        'pdf_link' => $session->pdf_link ? asset('storage/' . $session->pdf_link) : null,
                        'message' => 'Fetched saved results successfully.'
                    ]);

                } catch (\Exception $e) {
                    Log::error("❌ Error in viewCoupleResults: " . $e->getMessage());
                    return response()->json([
                        'success' => false,
                        'message' => 'Error generating results: ' . $e->getMessage()
                    ]);
