                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'groom')
                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                $matchCount = 0;
                $categoryScores = [];
                $categoryCounts = [];

                foreach ($questions as $q) {
                    $qid = $q->id;
                    $cat = $q->category;

                    if (!isset($categoryScores[$cat])) {
                        $categoryScores[$cat] = 0;
                        $categoryCounts[$cat] = 0;
                    }

                    if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {
                        $categoryCounts[$cat]++;
                        $score = ($brideAnswers[$qid] === $groomAnswers[$qid]) ? 100 : 60;
                        $categoryScores[$cat] += $score;
                        if ($score === 100) $matchCount++;
                    }
                }

                $categories = [];
                foreach ($categoryScores as $cat => $score) {
                    $categories[$cat] = round($score / max($categoryCounts[$cat], 1));
                }

                $compatibilityScore = $totalQuestions > 0 ? round(($matchCount / $totalQuestions) * 100) : 0;

                // === Personality Calculation (converted from JS)
                $calculateProfile = function ($answers, $name, $categories, $compatibilityScore) {
                    $traits = ['social' => 0, 'adventurous' => 0, 'traditional' => 0, 'ambitious' => 0, 'communicative' => 0, 'practical' => 0];

                    if (!empty($answers)) {
                        foreach ($answers as $val) {
                            if (is_numeric($val)) {
                                if ($val <= 1) $traits['social'] += 20;
                                if ($val == 2) $traits['practical'] += 20;
                                if ($val == 3) $traits['adventurous'] += 20;
                            } else {
                                $txt = strtolower($val);
                                if (str_contains($txt, 'advent') || str_contains($txt, 'explor')) $traits['adventurous'] += 30;
                                if (str_contains($txt, 'social') || str_contains($txt, 'friend')) $traits['social'] += 25;
                                if (str_contains($txt, 'stable') || str_contains($txt, 'traditional') || str_contains($txt, 'family')) $traits['traditional'] += 25;
                                if (str_contains($txt, 'career') || str_contains($txt, 'financial')) $traits['ambitious'] += 20;
                                if (str_contains($txt, 'talk') || str_contains($txt, 'communicat') || str_contains($txt, 'discuss')) $traits['communicative'] += 20;
                            }
                        }
                    } else {
                        // fallback from categories
                        foreach ($categories as $cat => $val) {
                            if (str_contains($cat, 'digital') || str_contains($cat, 'social') || str_contains($cat, 'dating')) $traits['social'] += $val;
                            if (str_contains($cat, 'advent') || str_contains($cat, 'travel')) $traits['adventurous'] += $val;
                            if (str_contains($cat, 'family') || str_contains($cat, 'trad')) $traits['traditional'] += $val;
                            if (str_contains($cat, 'career') || str_contains($cat, 'future') || str_contains($cat, 'money')) $traits['ambitious'] += $val;
                            if (str_contains($cat, 'communicat') || str_contains($cat, 'conflict')) $traits['communicative'] += $val;
                            if (str_contains($cat, 'lifestyle') || str_contains($cat, 'wellness')) $traits['practical'] += $val;
                        }
                    }

                    // normalize
                    foreach ($traits as $k => $v) {
                        $traits[$k] = min(100, $v);
                    }

                    $vibe = round(array_sum($traits) / count($traits));

                    $dominant = array_keys($traits, max($traits))[0] ?? 'social';
                    $types = [
                        'social' => ['type' => 'The Social Butterfly', 'emoji' => '🦋', 'desc' => 'Loves connecting with people and creating memorable experiences'],
