        public function viewCoupleResults_9($session_id)
            {
                $session = \App\CoupleAssessment::where('session_id', $session_id)->first();

                if (!$session || !$session->result_link) {
                    return response()->json(['success' => false, 'message' => 'Result not found.']);
                }

                // === Fetch Data ===
                $questions = \App\CoupleQuestion::where('is_active', 1)->get();
                $totalQuestions = $questions->count();

                $brideAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'bride')
                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                    ->where('answered_by', 'groom')
                    ->pluck('answer_text', 'question_id')
                    ->toArray();

                $matchCount = 0;
                $categoryScores = [];
                $categoryCounts = [];

                foreach ($questions as $q) {
                    $qid = $q->id;
                    $cat = $q->category;

                    if (!isset($categoryScores[$cat])) {
                        $categoryScores[$cat] = 0;
                        $categoryCounts[$cat] = 0;
                    }

                    if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {
                        $categoryCounts[$cat]++;
                        $score = ($brideAnswers[$qid] === $groomAnswers[$qid]) ? 100 : 60;
                        $categoryScores[$cat] += $score;
                        if ($score === 100) $matchCount++;
                    }
                }

                $categories = [];
                foreach ($categoryScores as $cat => $score) {
                    $categories[$cat] = round($score / max($categoryCounts[$cat], 1));
                }

                $compatibilityScore = $totalQuestions > 0 ? round(($matchCount / $totalQuestions) * 100) : 0;

                // === Personality Calculation (improved for text answers)
                $calculateProfile = function ($answers, $name, $categories, $compatibilityScore) {
                    $traits = ['social' => 0, 'adventurous' => 0, 'traditional' => 0, 'ambitious' => 0, 'communicative' => 0, 'practical' => 0];

                    if (!empty($answers)) {
                        foreach ($answers as $val) {
                            $val = trim(strtolower($val));

                            // Text-based keyword mapping
                            if (preg_match('/(advent|explor|travel)/', $val)) $traits['adventurous'] += 25;
                            if (preg_match('/(social|friend|party|public|network)/', $val)) $traits['social'] += 25;
                            if (preg_match('/(tradition|family|stable|culture)/', $val)) $traits['traditional'] += 25;
                            if (preg_match('/(career|financial|work|goal|success)/', $val)) $traits['ambitious'] += 25;
                            if (preg_match('/(communicat|talk|discuss|listen|share)/', $val)) $traits['communicative'] += 25;
                            if (preg_match('/(practical|simple|organize|routine|manage)/', $val)) $traits['practical'] += 25;
                        }
                    } else {
                        // fallback from categories
                        foreach ($categories as $cat => $val) {
                            if (str_contains($cat, 'digital') || str_contains($cat, 'social') || str_contains($cat, 'dating')) $traits['social'] += $val;
                            if (str_contains($cat, 'advent') || str_contains($cat, 'travel')) $traits['adventurous'] += $val;
                            if (str_contains($cat, 'family') || str_contains($cat, 'trad')) $traits['traditional'] += $val;
                            if (str_contains($cat, 'career') || str_contains($cat, 'future') || str_contains($cat, 'money')) $traits['ambitious'] += $val;
                            if (str_contains($cat, 'communicat') || str_contains($cat, 'conflict')) $traits['communicative'] += $val;
                            if (str_contains($cat, 'lifestyle') || str_contains($cat, 'wellness')) $traits['practical'] += $val;
                        }
                    }

                    // Normalize (convert to percentage)
                    $maxVal = max(1, max($traits));
                    foreach ($traits as $k => $v) {
                        $traits[$k] = round(($v / $maxVal) * 100);
                    }

                    // Compute average vibe
                    $vibe = round(array_sum($traits) / count($traits));

                    $dominant = array_keys($traits, max($traits))[0] ?? 'social';
                    $types = [
                        'social' => ['type' => 'The Social Butterfly', 'emoji' => '🦋', 'desc' => 'Loves connecting with people and creating memorable experiences'],
                        'adventurous' => ['type' => 'The Explorer', 'emoji' => '🌟', 'desc' => 'Always seeking new experiences and pushing boundaries'],
                        'traditional' => ['type' => 'The Anchor', 'emoji' => '⚓', 'desc' => 'Values stability, family traditions, and meaningful connections'],
                        'ambitious' => ['type' => 'The Achiever', 'emoji' => '🚀', 'desc' => 'Goal-oriented and driven to succeed in all aspects of life'],
                        'communicative' => ['type' => 'The Connector', 'emoji' => '💬', 'desc' => 'Excellent at expressing feelings and building understanding'],
                        'practical' => ['type' => 'The Realist', 'emoji' => '🎯', 'desc' => 'Grounded, logical, and focused on what truly matters'],
                    ];

                    $strengthMap = [
                        'social' => 'Great at building connections and maintaining relationships',
                        'adventurous' => 'Brings excitement and new perspectives to the relationship',
                        'traditional' => 'Provides stability and values long-term commitment',
                        'ambitious' => 'Motivated to build a successful future together',
                        'communicative' => 'Excellent at expressing needs and resolving conflicts',
                        'practical' => 'Makes thoughtful decisions and manages life efficiently',
                    ];

                    // sort top 3 traits
                    arsort($traits);
                    $top = array_slice(array_keys($traits), 0, 3);
                    $strengths = array_map(fn($t) => $strengthMap[$t], $top);

                    return [
                        'name' => $name,
                        'traits' => $traits,
                        'vibeScore' => $vibe,
                        'personality' => $types[$dominant]['type'],
                        'emoji' => $types[$dominant]['emoji'],
                        'description' => $types[$dominant]['desc'],
                        'strengths' => $strengths
                    ];
                };

                // === Generate real profiles
                $brideProfile = $calculateProfile($brideAnswers, $session->bride_name, $categories, $compatibilityScore);
                $groomProfile = $calculateProfile($groomAnswers, $session->groom_name, $categories, $compatibilityScore);

                // === Generate PDF if missing ===
                $pdfPath = $session->pdf_link;

                if (empty($pdfPath)) {
                    $html = view('pdfs.couple_results_full', [
                        'session' => $session,
                        'compatibilityScore' => $compatibilityScore,
                        'categories' => $categories,
                        'brideProfile' => $brideProfile,
                        'groomProfile' => $groomProfile
                    ])->render();

                    $pdf = PDF::loadHTML($html)->setPaper('a4', 'portrait');
                    $fileName = 'couple_pdfs/' . $session_id . '.pdf';
                    Storage::disk('public')->put($fileName, $pdf->output());

                    $session->pdf_link = $fileName;
                    $session->save();
                    $pdfPath = $fileName;
                }

                return response()->json([
                    'success' => true,
                    'session_id' => $session_id,
                    'bride_name' => $session->bride_name,
                    'groom_name' => $session->groom_name,
                    'compatibility_score' => $compatibilityScore,
                    'categories' => $categories,
                    'result_link' => $session->result_link,
                    'pdf_link' => $pdfPath,
                    'message' => 'Fetched saved results successfully.'
                ]);
            }

