        public function viewCoupleResults($session_id)
        {
            $session = \App\CoupleAssessment::where('session_id', $session_id)->first();

            if (!$session || !$session->result_link) {
                return response()->json(['success' => false, 'message' => 'Result not found.']);
            }

            $questions = \App\CoupleQuestion::where('is_active', 1)->get();

            // Fetch Answers
            $brideAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                ->where('answered_by', 'bride')
                ->pluck('answer_text', 'question_id')
                ->toArray();

            $groomAnswers = \App\CoupleAnswer::where('session_id', $session_id)
                ->where('answered_by', 'groom')
                ->pluck('answer_text', 'question_id')
                ->toArray();


            // === INITIALIZE ===
            $categoryScores = [];
            $categoryCounts = [];

            $brideCategory = [];
            $groomCategory = [];
            $brideCatCount = [];
            $groomCatCount = [];

            $totalSimilarity = 0;
            $answeredCount = 0;


            // === LOOP QUESTIONS ===
            foreach ($questions as $q) {

                $qid = $q->id;
                $cat = $q->category ?? 'General';

                // Initialize global category
                if (!isset($categoryScores[$cat])) {
                    $categoryScores[$cat] = 0;
                    $categoryCounts[$cat] = 0;

                    $brideCategory[$cat] = 0;
                    $groomCategory[$cat] = 0;
                    $brideCatCount[$cat] = 0;
                    $groomCatCount[$cat] = 0;
                }

                // === Bride category scoring ===
                if (isset($brideAnswers[$qid])) {
                    $brideCategory[$cat] += strlen(trim($brideAnswers[$qid])); // any scoring basis you want
                    $brideCatCount[$cat]++;
                }

                // === Groom category scoring ===
                if (isset($groomAnswers[$qid])) {
                    $groomCategory[$cat] += strlen(trim($groomAnswers[$qid]));
                    $groomCatCount[$cat]++;
                }

                // === Compatibility Similarity ===
                if (isset($brideAnswers[$qid]) && isset($groomAnswers[$qid])) {
                    $answeredCount++;

                    $similarity = 0;
                    similar_text(strtolower($brideAnswers[$qid]), strtolower($groomAnswers[$qid]), $similarity);
                    $categoryScores[$cat] += $similarity;
                    $categoryCounts[$cat]++;
                    $totalSimilarity += $similarity;
                }
            }


            // === FINAL COMBINED CATEGORY (EXISTING UI) ===
            $categories = [];
            foreach ($categoryScores as $cat => $score) {
                $categories[$cat] = round($score / max($categoryCounts[$cat], 1));
            }

            // === BRIDE INDIVIDUAL CATEGORY ===
            $brideCategories = [];
            foreach ($brideCategory as $cat => $score) {
                $brideCategories[$cat] = round($score / max($brideCatCount[$cat], 1));
            }

            // === GROOM INDIVIDUAL CATEGORY ===
            $groomCategories = [];
            foreach ($groomCategory as $cat => $score) {
                $groomCategories[$cat] = round($score / max($groomCatCount[$cat], 1));
            }


            // === COMPATIBILITY SCORE ===
            $compatibilityScore = $answeredCount > 0 ? round($totalSimilarity / $answeredCount) : 0;


            // === Personality using INDIVIDUAL CATEGORIES ===
            $makeProfile = function ($categories, $name) {

                $traits = [];
                foreach ($categories as $cat => $val) {
                    $traits[$cat] = $val;
                }

                if (empty($traits)) {
                    return [
                        'name' => $name,
                        'traits' => [],
                        'vibeScore' => 0,
                        'personality' => 'Not enough data',
                        'emoji' => '❓',
                        'description' => '',
                        'strengths' => []
                    ];
                }

                $vibeScore = round(array_sum($traits) / count($traits));

                $dominant = array_keys($traits, max($traits))[0];

                $top3 = array_slice(
                    array_keys(array_sort($traits, SORT_DESC)),
                    0,
                    3
                );

                $strengths = array_map(function ($cat) {
                    return "$cat is a strong positive trait area.";
                }, $top3);

                return [
                    'name' => $name,
                    'traits' => $traits,
                    'vibeScore' => $vibeScore,
                    'personality' => "Strong in $dominant",
                    'emoji' => "🌟",
                    'description' => "Shows strong compatibility in $dominant.",
                    'strengths' => $strengths,
                ];
            };


            $brideProfile = $makeProfile($brideCategories, $session->bride_name);
            $groomProfile = $makeProfile($groomCategories, $session->groom_name);


            // === Ensure PDF exists (same as before) ===
            if (empty($session->pdf_link)) {

                $html = view('pdfs.couple_results_full', [
                    'session' => $session,
                    'compatibilityScore' => $compatibilityScore,
                    'categories' => $categories,
                    'brideProfile' => $brideProfile,
                    'groomProfile' => $groomProfile
                ])->render();

                $pdf = \PDF::loadHTML($html)->setPaper('a4', 'portrait');
                $fileName = 'couple_pdfs/' . $session_id . '.pdf';

                \Storage::disk('public')->put($fileName, $pdf->output());
                $session->pdf_link = $fileName;
                $session->save();
            }


            // === FINAL RESPONSE ===
            return response()->json([
                'success' => true,
                'session_id' => $session_id,
                'bride_name' => $session->bride_name,
                'groom_name' => $session->groom_name,
                'assessment_type' => $session->assessment_type,

                'compatibility_score' => $compatibilityScore,

                // NEW INDIVIDUAL CATEGORY LISTS
                'bride_categories' => $brideCategories,
                'groom_categories' => $groomCategories,

                // merged category list (for the main chart)
                'categories' => $categories,

                'bride_profile' => $brideProfile,
                'groom_profile' => $groomProfile,

                'result_link' => $session->result_link,
                'pdf_link' => $session->pdf_link,
                'message' => 'Fetched saved results successfully.'
            ]);
        }
    

         public function retakeCoupleAssessment_2(Request $request)
            {
                $oldSessionId = $request->old_session_id;

                // Get old session
                $old = \App\CoupleAssessment::where('session_id', $oldSessionId)->first();

                if (!$old) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Old session not found'
                    ]);
                }

                // 🚫 If a retake was already initiated by partner
                if (!empty($old->retake_session_id)) {
                    return response()->json([
                        'success' => false,
                        'already_started' => true,
                        'message' => 'Your partner has already initiated a new assessment.',
                        'retake_session_id' => $old->retake_session_id,
                        'share_link' => url('/couplevibe?session=' . $old->retake_session_id)
                    ]);
