        public function retakeCoupleAssessment_4(Request $request)
            {
                $oldSessionId = $request->old_session_id;

                // Get old session
                $old = \App\CoupleAssessment::where('session_id', $oldSessionId)->first();

                if (!$old) {
                    return response()->json([
                        'success' => false,
                        'message' => 'Old session not found'
                    ]);
                }

                // 🚫 If a retake was already initiated by partner
                if (!empty($old->retake_session_id)) {
                    return response()->json([
                        'success' => false,
                        'already_started' => true,
                        'message' => 'Your partner has already initiated a new assessment.',
                        'retake_session_id' => $old->retake_session_id,
                        'share_link' => url('/couplevibe?session=' . $old->retake_session_id)
                    ]);
                }

                // Determine whether this is premium or free (defensive)
                $atype = strtolower(trim((string)$old->assessment_type));
                $isPremium = (strpos($atype, 'Premium') !== false);

                $questionOrder = [];

                if ($isPremium) {
                    // Premium → random 20 active premium questions
                    $questionOrder = DB::table('couple_questions')
                        ->where('is_active', 1)
                        ->where('assessment_type', 'Premium') // remove this if your questions don't have this flag
                        ->inRandomOrder()
                        ->limit(20)
                        ->pluck('id')
                        ->toArray();

                    shuffle($questionOrder);
                } else {
                    // Free → EXACTLY 5 questions: one random from each free category
                    $freeCategories = [
                        'Communication',
                        'Trust & Security',
                        'Emotional Support',
                        'Family & Social',
                        'Future Planning'
                    ];

                    $selected = [];

                    foreach ($freeCategories as $cat) {
                        $q = DB::table('couple_questions')
                            ->where('category', $cat)
                            ->where('is_active', 1)
                            ->where('assessment_type', 'free') // ensure free question selection
                            ->inRandomOrder()
                            ->first();

                        if ($q) {
                            $selected[] = $q->id;
                        }
                    }

                    // If any category missed a question (edge case), fill from other free active questions
                    if (count($selected) < 5) {
                        $needed = 5 - count($selected);
                        $fallback = DB::table('couple_questions')
                            ->where('is_active', 1)
                            ->where('assessment_type', 'free')
                            ->whereNotIn('id', $selected)
                            ->inRandomOrder()
                            ->limit($needed)
                            ->pluck('id')
                            ->toArray();

                        $selected = array_merge($selected, $fallback);
                    }

                    // Ensure exactly 5 and random order
                    $selected = array_slice($selected, 0, 5);
                    shuffle($selected);
                    $questionOrder = $selected;
                }

                // Generate new session id (same pattern)
                $newSessionId = 'couple_' . rand(100,999) . '_vibe_' . time() . '_' . Str::random(8);

                // Create new assessment and save question_order JSON
                $new = \App\CoupleAssessment::create([
                    'session_id'      => $newSessionId,
                    'bride_name'      => $old->bride_name,
                    'bride_email'     => $old->bride_email,
                    'bride_mobile'    => $old->bride_mobile,
                    'groom_name'      => $old->groom_name,
                    'groom_email'     => $old->groom_email,
                    'groom_mobile'    => $old->groom_mobile,
                    'creator'         => $old->creator,
                    'assessment_type' => $old->assessment_type,
                    'status'          => 'created',
                    'question_order'  => json_encode($questionOrder)
                ]);

                // Save retake_session_id on old record
                $old->retake_session_id = $newSessionId;
                $old->save();

                $shareLink = url('/couplevibe?session=' . $newSessionId);

                return response()->json([
                    'success' => true,
                    'new_session_id' => $new->session_id,
                    'share_link' => $shareLink,
                    'bride_name'   => $new->bride_name,
                    'bride_email'  => $new->bride_email,
                    'bride_mobile' => $new->bride_mobile,
                    'groom_name'   => $new->groom_name,
                    'groom_email'  => $new->groom_email,
                    'groom_mobile' => $new->groom_mobile,
                    'assessment_type' => $new->assessment_type,
                    'question_order' => $questionOrder // helpful for debugging frontend
                ]);
            }



