        public function createPremiumCoupleSession(Request $request)
            {
                $validator = Validator::make($request->all(), [
                    'bride_name' => 'required|min:2|max:150',
                    'bride_email' => 'required|email',
                    'bride_mobile' => 'required|digits:10',
                    'groom_name' => 'required|min:2|max:150',
                    'groom_email' => 'required|email',
                    'groom_mobile' => 'required|digits:10',
                    'creator' => 'required|in:bride,groom,family',
                ]);

                if ($validator->fails()) {
                    return response()->json(['success' => false, 'message' => $validator->errors()->first()], 422);
                }

                $couple = CoupleAssessment::create([
                    'bride_name' => $request->bride_name,
                    'bride_email' => $request->bride_email,
                    'bride_mobile' => $request->bride_mobile,
                    'groom_name' => $request->groom_name,
                    'groom_email' => $request->groom_email,
                    'groom_mobile' => $request->groom_mobile,
                    'creator' => $request->creator,
                    'assessment_type' => 'Tried Premium',   // initial value
                    'status' => 'Pending Payment'
                ]);

                $sessionId = 'couple_' . $couple->id . '_vibe_' . time() . '_' . Str::random(8);

                $couple->update(['session_id' => $sessionId]);

                //$request->session()->put('couple_assessment_otp', $otp);   // if you generate OTP
                $request->session()->put('couple_session_id', $sessionId);

                return response()->json([
                    'success' => true,
                    'session_id' => $sessionId,
                    'couple_id' => $couple->id
                ]);
            }

        public function initiatePremiumPayment(Request $request)
            {
                $sessionId = $request->query('session');
                $amount = $request->query('amount', 199);

                // simple check: session must exist and status Pending Payment
                $couple = CoupleAssessment::where('session_id', $sessionId)->first();
                if (!$couple) {
                    return redirect()->route('website.couplecompatibility')->with('error', 'Invalid session');
                }

                // return a view that auto-triggers payment
                return view('payments.initiate_premium', compact('sessionId', 'amount'));
            }

        public function premiumPaymentSuccess(Request $request)
            {
                $sessionId = $request->session_id;

                $couple = CoupleAssessment::where('session_id', $sessionId)->first();

                if (!$couple) {
                    return response()->json(['success' => false, 'message' => 'Session not found']);
                }

                // Update final premium status
                $couple->update([
                    'assessment_type' => 'Premium',
                    'status'          => 'Payment Completed'
                ]);

                return response()->json([
                    'success' => true,
                    'message' => 'Payment updated'
                ]);
            } 

