        public function initiatePremiumPaymentCouple(Request $request)
            {
                $sessionId = $request->session_id;

                $couple = CoupleAssessment::where('session_id', $sessionId)->first();

                if (!$couple) {
                    return response()->json(["success" => false]);
                }

                $orderId = "ORDER_" . uniqid();
                $amount = 199;

                $paytmParams = [
                    "body" => [
                        "requestType" => "Payment",
                        "mid" => "aUrqBh85345734866262",
                        "websiteName" => "DEFAULT",
                        "orderId" => $orderId,
                        //"callbackUrl" => "https://planawedding.in/couplevibe?payment=success",
                        //"callbackUrl" => url('/couplevibe?payment=success'),
                        "callbackUrl" => url('/premium-payment-callback?session=' . $sessionId),

                        "txnAmount" => [
                            "value" => (string)$amount,
                            "currency" => "INR"
                        ],
                        "userInfo" => [
                            //"custId" => (string)$couple->id
                             "custId" => "CoupleCompatible_" . $couple->id
                        ]
                    ]
                ];

                $signature = $this->generateSignature(
                    json_encode($paytmParams["body"], JSON_UNESCAPED_SLASHES),
                    "X_b1mPyvIOMp@ry0"
                );

                $paytmParams["head"]["signature"] = $signature;

                $postData = json_encode($paytmParams, JSON_UNESCAPED_SLASHES);

                $url = "https://secure.paytm.in/theia/api/v1/initiateTransaction?mid=aUrqBh85345734866262&orderId=$orderId";

                $ch = curl_init($url);
                curl_setopt($ch, CURLOPT_POST, 1);
                curl_setopt($ch, CURLOPT_POSTFIELDS, $postData);
                curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
                curl_setopt($ch, CURLOPT_HTTPHEADER, ["Content-Type: application/json"]);
                $response = curl_exec($ch);
                $data = json_decode($response, true);


                $payment = new Payment();

                $payment->couple_compatibe_id = $couple->id;

                $payment->orderid = $orderId;
                $payment->payable_type = 'Couple Compatible';
                $payment->status = '';
                $payment->reference = '';
                $payment->payable_id = $couple->id;
                $payment->type = 'Couple Compatible Web';

                $payment->save();
                
                return response()->json([
                    "success" => true,
                    "orderId" => $orderId,
                    "txnToken" => $data['body']['txnToken'],
                    "amount" => $amount
                ]);
            }

