        public function premiumPaymentCallback_1(Request $request)
            {
                try {
                    $orderId   = $request->orderId ?? null;
                    $txnid     = $request->TXNID ?? null;
                    $status    = $request->STATUS ?? null;
                    $sessionId = $request->session ?? null;

                    if (!$sessionId) {
                        return redirect('/couplevibe?payment=failed');
                    }

                    // Fetch couple by session ID
                    $couple = CoupleAssessment::where('session_id', $sessionId)->first();

                    if (!$couple) {
                        return redirect('/couplevibe?payment=failed');
                    }

                    // ONLY update when payment is successful
                    if ($status === "TXN_SUCCESS" || $status === "01") {

                        $couple->update([
                            "assessment_type" => "Premium",
