        public function sendCoupleOTP(Request $request)
        {
            if ($request->ajax()) {

                $name   = $request->name ?? '';
                $email  = $request->email ?? '';
                $mobile = $request->mobile;

                if (!$mobile) {
                    return response()->json(['status' => 0, 'msg' => 'Mobile number missing']);
                }

                // Generate OTP
                $otp = rand(1000, 9999);

                // Save OTP in session
                $request->session()->put('couple_assessment_otp', $otp);

                // STORE CUSTOMER LIKE YOUR OLD CODE
                $customer = new Customer();
                $customer->name = $name;
                $customer->email = $email;
                $customer->mobile = $mobile;
                $customer->lead_source = 'Couple Compatibility Web Page';
                $customer->save();

                // Send SMS
                $message = "$otp is your OTP from Plan a wedding -Variety Vintage Technologies Pvt Ltd";
                $message = urlencode($message);

                $ch = curl_init();
                curl_setopt($ch, CURLOPT_URL,
                    "https://smsapi.24x7sms.com/api_2.0/SendSMS.aspx?APIKEY=4AbdiHVSDzt&MobileNo={$mobile}&SenderID=planaw&Message=$message&ServiceName=TEMPLATE_BASED"
                );
                curl_setopt($ch, CURLOPT_RETURNTRANSFER, TRUE);
                curl_exec($ch);
                curl_close($ch);
 


                 return response()->json([
                        'message' => 'Thank you for submitting your details, our team will connect with you shortly.',
                        'status' => '1',
                        'send_otp' => $otp, 
                    ]);
            }
        }

