    public function savenewbuyleadform(Request $request)
    {
        if ($request->ajax())
        {
            $validator = \Validator::make($request->all(), [
                'client_name' => 'required',
                'client_mobile' => 'required',
            ]);

            if ($validator->fails())
            {
                return response()->json([
                    'message' => $validator->errors()->first(),
                    'status' => '0',
                ]);
            }
            else
            {
                // Format dates and times
                date_default_timezone_set('Asia/Kolkata');
                $leadtime = date("d-m-Y H:i:s");
                $expirytime = date('Y-m-d', strtotime('+7 days'));

                $connected = $request->assignid;
                
                // Get User for executive name
                $user = \App\User::find($connected);
                $executive_name = $user ? $user->name : 'Admin';

                // Format Wedding Date if fixed
                $wedding_date_formatted = NULL;
                if ($request->is_date_fixed == 'Yes' && !empty($request->wedding_date)) {
                    $wedding_date_formatted = date('Y-m-d', strtotime($request->wedding_date));
                }

                $custombuylead = new CustombuyLead();
                
                // Step 1: Client Info
                $custombuylead->customer_name = $request->client_name;
                $custombuylead->customer_mobile = $request->client_mobile;
                
                // Step 2: Date Info
                $custombuylead->weddingdate_fixed = $request->is_date_fixed == 'Yes' ? 'dateyes' : 'dateno';
                if ($request->is_date_fixed == 'Yes') {
                    $custombuylead->wedding_date = $wedding_date_formatted;
                    $custombuylead->wedding_approx_period = NULL;
                } else {
                    $custombuylead->wedding_date = NULL;
                    $custombuylead->wedding_approx_period = $request->approx_wedding_date;
                }

                // Step 3: Location Info
                $custombuylead->city = $request->client_city;
                $custombuylead->location = $request->client_location;
                $custombuylead->is_wedding_location_different = $request->is_wedding_location_different;
                if ($request->is_wedding_location_different == 'Yes') {
                    $custombuylead->wedding_location = $request->wedding_location;
                } else {
                    $custombuylead->wedding_location = NULL;
                }

                // Step 4 & 5: Traditions & Customs
                $custombuylead->wedding_type = $request->wedding_type;
                $custombuylead->wedding_community = $request->wedding_community;

                // Step 6: Wedding Services
                if($request->has('wedding_services')) {
                    $custombuylead->weddinglist_items = implode(',', $request->wedding_services);
                    $weddinglist_items_array = $request->wedding_services;
                } else {
                    $custombuylead->weddinglist_items = NULL;
                    $weddinglist_items_array = [];
                }

                // Guests & Budget
                if (in_array("Complete Wedding Planning", $weddinglist_items_array) || in_array("Venue", $weddinglist_items_array) || in_array("Catering", $weddinglist_items_array)) {
                    $custombuylead->complete_guestnumber = $request->approx_guests;
                }
                
                if (in_array("Complete Wedding Planning", $weddinglist_items_array) || in_array("Venue", $weddinglist_items_array)) {
                    $custombuylead->complete_weddingbudget = $request->approx_budget;
                }

                // Venue specific
                if (in_array("Venue", $weddinglist_items_array)) {
                    $custombuylead->venue_fixed = $request->is_venue_fixed;
                    if ($request->is_venue_fixed == 'venueyes') {
                        $custombuylead->venuename = $request->venue_name;
                        $custombuylead->venue_allow_outsidevendors = $request->venue_allow_outside;
                        $custombuylead->venuedetail = NULL;
                    } else {
                        $custombuylead->venuename = NULL;
                        $custombuylead->venue_allow_outsidevendors = NULL;
                        $custombuylead->venuedetail = $request->venue_details_help;
                    }
                }

                // Defaults & Timestamps
                $custombuylead->buyleads_lead_date = $leadtime;
                $custombuylead->buyleads_expiry_date = $expirytime;
                $custombuylead->connected_by = $connected;
                $custombuylead->move_toleads = 0;
                $custombuylead->buyleads_package_type = 'wedding';
                $custombuylead->buyleads_purchase_allowed = 3;
                $custombuylead->preferred_connect_time = !empty($request->preferred_connect_time) ? date('d/m/Y h:i A', strtotime($request->preferred_connect_time)) : NULL;
                $custombuylead->buyleads_status = 'not-purchased';
                $custombuylead->buyleads_type = 'Buy Lead';
                $custombuylead->buyleads_executive_name = $executive_name;
                $custombuylead->lead_status = 'Pending';
                $custombuylead->lead_source = 'Internal';
                $custombuylead->lead_source_show = 'PAW Lead';
                $custombuylead->buyleads_event_category = 'End to end Wedding Services';
                $custombuylead->sequence_of_events = is_array($request->sequence_of_events) ? implode(',', $request->sequence_of_events) : $request->sequence_of_events;
                $custombuylead->dest_type = is_array($request->dest_type) ? implode(',', $request->dest_type) : $request->dest_type;
                $custombuylead->dest_duration = is_array($request->dest_duration) ? implode(',', $request->dest_duration) : $request->dest_duration;
                $custombuylead->decor_type = is_array($request->decor_type) ? implode(',', $request->decor_type) : $request->decor_type;
                $custombuylead->additional_remarks = $request->additional_remarks;

                $whomLeadTo = is_array($request->whom_lead_to) ? implode(',', $request->whom_lead_to) : $request->whom_lead_to;
                $whomLeadTo = str_replace('makeup artist', 'makeup-artists', $whomLeadTo);
                if($whomLeadTo) { $custombuylead->buyleads_package_type = $whomLeadTo; }
                $custombuylead->buy_leads_description = $request->whom_lead_desc_wedding_planner;
                $custombuylead->buy_leads_description_lead_description_photovideo = $request->whom_lead_desc_photo_video;
                $custombuylead->buy_leads_description_lead_description_catering = $request->whom_lead_desc_catering;
                $custombuylead->buy_leads_description_lead_description_flower = $request->whom_lead_desc_flower;
                $custombuylead->buy_leads_description_lead_description_mehendi = $request->whom_lead_desc_mehendi;
                $custombuylead->buy_leads_description_lead_description_priests = $request->whom_lead_desc_priests;
                $custombuylead->buy_leads_description_lead_description_dj = $request->whom_lead_desc_dj;
                $custombuylead->buy_leads_description_lead_description_venue = $request->whom_lead_desc_venue;
                $custombuylead->buy_leads_description_lead_description_makeup = $request->whom_lead_desc_makeup;

                if(is_array($request->whom_lead_to)) {
                    if(in_array('wedding', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed = 3; $custombuylead->buyleads_event_category = 'End to end Wedding Services'; }
                    if(in_array('photo&videographer', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_photovideo = 3; $custombuylead->buyleads_event_category_photovideo = 'Photo & Videographer'; }
                    if(in_array('catering', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_caterers = 3; $custombuylead->buyleads_event_category_catering = 'Caterers'; }
                    if(in_array('flower-decorators', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_flower = 3; $custombuylead->buyleads_event_category_flower = 'Flower Decorators'; }
                    if(in_array('mehendi artist', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_mehendi = 3; $custombuylead->buyleads_event_category_mehendi = 'Mehendi Artist'; }
                    if(in_array('priests', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_priest = 3; $custombuylead->buyleads_event_category_priest = 'Priests'; }
                    if(in_array('dj', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_dj = 3; $custombuylead->buyleads_event_category_dj = 'DJ'; }
                    if(in_array('Venue', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_venue = 3; $custombuylead->buyleads_event_category_venue = 'Venue'; }
                    if(in_array('makeup artist', $request->whom_lead_to)) { $custombuylead->buyleads_purchase_allowed_makeup = 3; $custombuylead->buyleads_event_category_makeup = 'Makeup'; }
                }

                try {
                    if($custombuylead->save())
                    {
                        return response()->json([
                            'message' => '',
                            'status' => '1',
                        ]);
                    }
                    else
                    {
                        return response()->json([
                            'message' => 'An error occurred',
                            'status' => '0',
                        ]);
                    }
                } catch (\Exception $e) {
                    \Log::error('Save Exception: ' . $e->getMessage());
                    $arr = $custombuylead->getAttributes();
                    $bad_fields = [];
                    foreach ($arr as $k => $v) {
                        if (is_array($v)) {
                            $bad_fields[] = $k;
                        }
                    }
                    return response()->json([
                        'message' => 'Exception: Array to string conversion on fields: ' . implode(',', $bad_fields) . ' - ' . $e->getMessage(),
                        'status' => '0',
                    ]);
                }
            }
        }
    }

